@app.route("/api/annonce/jeux")
def get_annonces_jeux():
    global DB
    DB = load_data()
    annonces = DB.get("annonces_jeux", [])
    codes = DB.get("codes", {})

    # 1) SECURITE : ne garder que les annonces d'organisateurs ACTIFS.
    #    Quand un ancien organisateur est desactive, son annonce disparait
    #    automatiquement de tous les espaces (plus de jeu fantome a rembourser).
    def _org_actif(a):
        info = codes.get(a.get("code_org"))
        return bool(info and info.get("actif"))
    annonces = [a for a in annonces if _org_actif(a)]

    # 2) Toutes les joueuses voient TOUS les jeux des organisatrices ACTIVES.
    #    Cloisonnement par organisatrice DÉSACTIVÉ (à la demande de l'admin) :
    #    une joueuse peut participer aux tournois de n'importe quelle organisatrice
    #    active, y compris une nouvelle arrivée. Le paramètre "code" reste accepté
    #    mais ne restreint plus l'affichage.
    return jsonify(annonces)

@app.route("/api/annonce/ventes", methods=["POST"])
def annonce_ventes():
    """ORGANISATEUR — Ouvre ou ferme les ventes de son jeu annonce.
    Quand c'est ferme, plus aucune joueuse ne peut commander (bloque cote serveur)."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False, "msg": "Accès refusé"}), 403
    d = request.get_json(silent=True) or {}
    ouvertes = bool(d.get("ouvertes", False))
    trouve = False
    for a in DB.get("annonces_jeux", []):
        if a.get("code_org") == s["code"]:
            a["ventes_ouvertes"] = ouvertes
            trouve = True
            break  # une seule annonce active par organisateur
    if not trouve:
        return jsonify({"ok": False, "msg": "Aucun jeu annoncé à clôturer."}), 404
    save_data()
    return jsonify({"ok": True, "ventes_ouvertes": ouvertes})

