import random as _rnd_verif

# === MOTEUR DE VERIFICATION AUTOMATIQUE (style EuroMillions) ===
# Le serveur RECALCULE les numéros d'un ticket à partir de son numéro de série,
# exactement comme le générateur, puis compare aux boules tirées. Fiable, instantané.

_P6_COLS = [("B", 1, 15), ("I", 16, 30), ("N", 31, 45), ("G", 46, 60), ("O", 61, 75)]

def _p6_gen_carte(rng):
    carte = {}
    for lettre, a, b in _P6_COLS:
        nb = 4 if lettre == "N" else 5
        carte[lettre] = tuple(rng.sample(range(a, b + 1), nb))
    return carte

def _p6_signature(carte):
    return tuple(carte[l] for l, _, _ in _P6_COLS)

def _p6_numeros(serie_start, serial_cible):
    """Recalcule les 24 numéros du ticket P6 pour ce serial (même logique que generate_p6)."""
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(600000 + serie_start)
    vus = set()
    produits = 0
    cible = serial_cible - serie_start
    garde = 0
    while garde < 6000:
        garde += 1
        carte = _p6_gen_carte(rng)
        sig = _p6_signature(carte)
        if sig in vus:
            continue
        vus.add(sig)
        if produits == cible:
            nums = []
            for l, _, _ in _P6_COLS:
                nums.extend(carte[l])
            return nums
        produits += 1
    return None

_OHANA_COLS = [("B", 1, 15), ("I", 16, 30), ("N", 31, 45), ("G", 46, 60), ("O", 61, 75)]

def _ohana_gen_carte(rng):
    carte = {}
    for lettre, a, b in _OHANA_COLS:
        nb = 8 if lettre == "N" else 10
        nums = rng.sample(range(a, b + 1), nb)
        carte[lettre] = tuple((nums[2 * i], nums[2 * i + 1]) for i in range(nb // 2))
    return carte

def _ohana_signature(carte):
    return tuple(carte[l] for l, _, _ in _OHANA_COLS)

def _ohana_cellules(serie_start, serial_cible):
    """Recalcule les 24 cases (paires de 2 numéros) d'une carte OHANA 75 ORIGINAL."""
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(750100 + serie_start)
    vus = set()
    produits = 0
    cible = serial_cible - serie_start
    garde = 0
    while garde < 6000:
        garde += 1
        carte = _ohana_gen_carte(rng)
        sig = _ohana_signature(carte)
        if sig in vus:
            continue
        vus.add(sig)
        if produits == cible:
            cellules = []
            for l, _, _ in _OHANA_COLS:
                for paire in carte[l]:
                    cellules.append((l, [paire[0], paire[1]]))
            return cellules  # 24 cases (B5 + I5 + N4 + G5 + O5)
        produits += 1
    return None

def _ohana10b_lignes(serie_start, serial_cible):
    """OHANA 75 — 10 BOULES : 5 lignes × 2 numéros. Graine 750000."""
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(750000 + serie_start)
    vus = set(); produits = 0; cible = serial_cible - serie_start; garde = 0
    while garde < 6000:
        garde += 1
        nums = {l: sorted(rng.sample(range(a, b + 1), 2)) for l, a, b in _OHANA_COLS}
        sig = tuple(tuple(nums[l]) for l, _, _ in _OHANA_COLS)
        if sig in vus:
            continue
        vus.add(sig)
        if produits == cible:
            return [(l, [nums[l][0], nums[l][1]]) for l, _, _ in _OHANA_COLS]
        produits += 1
    return None

def _ohana8b_lignes(serie_start, serial_cible):
    """OHANA 75 — 8 BOULES : 4 plages sur 5 (plage absente aléatoire) × 2. Graine 758000."""
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(758000 + serie_start)
    vus = set(); produits = 0; cible = serial_cible - serie_start; garde = 0
    while garde < 6000:
        garde += 1
        sautee = rng.randrange(5)
        grille = []
        for idx, (lettre, a, b) in enumerate(_OHANA_COLS):
            if idx == sautee:
                continue
            grille.append((lettre, tuple(sorted(rng.sample(range(a, b + 1), 2)))))
        sig = tuple(grille)
        if sig in vus:
            continue
        vus.add(sig)
        if produits == cible:
            return [(l, [p[0], p[1]]) for (l, p) in grille]
        produits += 1
    return None

def _variante_cle(jeu):
    ju = (jeu or "").upper()
    if "P6" in ju:
        return "P6"
    if "OHANA" in ju:
        if "8 BOULE" in ju:
            return "OHANA8"
        if "10 BOULE" in ju:
            return "OHANA10"
        return "OHANAORIG"
    if "DOLLAR" in ju:
        return "DOLLAR"
    if "FRANC" in ju:
        return "F500"
    if "40 BOULE" in ju:
        return "B40"
    if "60 BOULE" in ju:
        return "B60"
    if "COIN" in ju:
        return "4COIN"
    if "TRIPLE" in ju or "ACTION" in ju or "TA75" in ju:
        return "TA75"
    if "ALOHA" in ju:
        return "ALOHA75"
    if "BINGO BALL" in ju:
        return "BINGOBALL"
    if "BROWN" in ju:
        return "BROWN8"
    if "FLASH" in ju or "QUINE" in ju:
        return "FLASHQ"
    if "KAI" in ju:
        return "KAIB"
    return ju.split()[0] if ju.strip() else ""

# Jeux "une boule" (1 numéro = 1 case), reproductibles depuis la réparation (graine).
# cle -> (graine, nb_numeros, min, max). Doit coller aux générateurs réparés.
_JEUX_PLATS = {
    "DOLLAR": (810000, 9, 1, 75),
    "F500":   (850000, 10, 1, 75),
    "B40":    (840000, 10, 1, 40),
    "B60":    (860000, 8, 1, 60),
}

def _regen_plat(cle, serie_start, serial_cible):
    cfg = _JEUX_PLATS.get(cle)
    if not cfg:
        return None
    seed_base, count, lo, hi = cfg
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(seed_base + serie_start)
    nums = None
    for _ in range((serial_cible - serie_start) + 1):
        nums = sorted(rng.sample(range(lo, hi + 1), count))
    return nums

# 4 COIN : 4 colonnes par plage (1-15, 16-30, 46-60, 61-75), milieu vide, FREE centre.
# 16 numéros, "une boule", carton plein. Graine 820000 (doit coller au générateur réparé).
_4COIN_PLAGES = [(1, 15), (16, 30), None, (46, 60), (61, 75)]

def _regen_4coin(serie_start, serial_cible):
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(820000 + serie_start)
    cols = None
    for _ in range((serial_cible - serie_start) + 1):
        cols = []
        for p in _4COIN_PLAGES:
            if p is None:
                cols.append(None)
            else:
                cols.append(sorted(rng.sample(range(p[0], p[1] + 1), 4)))
    nums = []
    for cset in cols:
        if cset:
            nums.extend(cset)
    return nums  # 16 numéros

# TRIPLE ACTION 75 : 5 groupes × 3 numéros (plages 1-15/16-30/31-45/46-60/61-75).
# 15 numéros, "une boule", carton plein. Graine 700000 (doit coller au générateur réparé).
_TA75_RANGES = [(1, 15), (16, 30), (31, 45), (46, 60), (61, 75)]

def _ta75_groupes(serie_start, serial_cible):
    """TRIPLE ACTION 75 : 5 groupes de 3 numéros. Un groupe est coché si UN de ses
    3 numéros sort (boule pour 3). Renvoie [(label, [n1,n2,n3]), ...]."""
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(700000 + serie_start)
    grille = None
    for _ in range((serial_cible - serie_start) + 1):
        grille = [sorted(rng.sample(range(lo, hi + 1), 3)) for (lo, hi) in _TA75_RANGES]
    labels = ["B", "I", "N", "G", "O"]
    return [(labels[i], grille[i]) for i in range(5)]  # 5 groupes de 3

# === NOUVEAUX JEUX (régénération validée à l'identique des générateurs) ===
# Chaque fonction reproduit EXACTEMENT la boucle du générateur PDF (graine +
# saut des doublons via signature) et renvoie la liste PLATE des numéros du carton.
# Carton plein = tous ces numéros sont sortis.
_ALOHA_PLAGES = [(1, 15), (16, 30), (31, 45), (46, 60), (61, 75)]
_FLASH_DECADES = [(1, 9)] + [(d, d + 9) for d in range(10, 80, 10)] + [(80, 90)]
_BROWN_LETTRES = ["B", "R", "O", "W", "N"]

def _regen_aloha75(serie_start, serial_cible, maxiter=8000):
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(751000 + serie_start)
    vus = set(); produits = 0; it = 0
    while it < maxiter:
        it += 1
        cols = [sorted(rng.sample(range(a, b + 1), 2)) for a, b in _ALOHA_PLAGES]
        sig = tuple(tuple(c) for c in cols)
        if sig in vus:
            continue
        vus.add(sig)
        if serie_start + produits == serial_cible:
            return [n for c in cols for n in c]   # 10 numéros
        produits += 1
    return None

def _regen_bingoball(serie_start, serial_cible, maxiter=8000):
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(752000 + serie_start)
    vus = set(); produits = 0; it = 0
    while it < maxiter:
        it += 1
        centre = sorted(rng.sample(range(31, 46), 3))
        ligne = [rng.randint(1, 15), rng.randint(16, 30), centre[1], rng.randint(46, 60), rng.randint(61, 75)]
        sig = (tuple(ligne), tuple(centre))
        if sig in vus:
            continue
        vus.add(sig)
        if serie_start + produits == serial_cible:
            return sorted(set(ligne) | set(centre))   # 7 numéros uniques (croix)
        produits += 1
    return None

def _regen_brown8(serie_start, serial_cible, maxiter=8000):
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(753000 + serie_start)
    vus = set(); produits = 0; it = 0
    while it < maxiter:
        it += 1
        nums = {
            "B": sorted(rng.sample(range(1, 16), 2)),
            "R": [rng.randint(16, 30)],
            "O": sorted(rng.sample(range(31, 46), 2)),
            "W": [rng.randint(46, 60)],
            "N": sorted(rng.sample(range(61, 76), 2)),
        }
        sig = tuple((l, tuple(nums[l])) for l in _BROWN_LETTRES)
        if sig in vus:
            continue
        vus.add(sig)
        if serie_start + produits == serial_cible:
            return [n for l in _BROWN_LETTRES for n in nums[l]]   # 8 numéros
        produits += 1
    return None

def _regen_kai(serie_start, serial_cible, maxiter=8000):
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(754000 + serie_start)
    vus = set(); produits = 0; it = 0
    while it < maxiter:
        it += 1
        c0 = sorted(rng.sample(range(1, 11), 2))
        c1 = sorted(rng.sample(range(11, 21), 3))
        c2 = sorted(rng.sample(range(21, 31), 2))
        grille = [[c0[0], c1[0], None], [c0[1], c1[1], c2[0]], [None, c1[2], c2[1]]]
        sig = tuple(tuple(("X" if v is None else v) for v in row) for row in grille)
        if sig in vus:
            continue
        vus.add(sig)
        if serie_start + produits == serial_cible:
            return c0 + c1 + c2   # 7 numéros
        produits += 1
    return None

def _regen_flashq(serie_start, serial_cible, maxiter=8000):
    serie_start = int(serie_start); serial_cible = int(serial_cible)
    if serial_cible < serie_start:
        return None
    rng = _rnd_verif.Random(755000 + serie_start)
    vus = set(); produits = 0; it = 0
    while it < maxiter:
        it += 1
        nums = [rng.randint(a, b) for (a, b) in _FLASH_DECADES]
        sig = tuple(nums)
        if sig in vus:
            continue
        vus.add(sig)
        if serie_start + produits == serial_cible:
            return list(nums)   # 9 numéros (1 par dizaine)
        produits += 1
    return None

def _serie_start_pour(jeu, serial):
    """Retrouve la série de départ du lot, en privilégiant la MÊME variante de jeu
    (les graines diffèrent : P6/OHANA original/10b/8b)."""
    serial = int(serial)
    cle = _variante_cle(jeu)
    couvrants = []
    for c in DB.get("commandes", []):
        if int(c.get("serie_start", 0)) <= serial <= int(c.get("serie_end", 0)):
            couvrants.append((_variante_cle(c.get("jeu", "")), int(c.get("serie_start"))))
    if not couvrants:
        return None
    for vc, ss in couvrants:
        if vc == cle:
            return ss
    return couvrants[0][1]

def _verifier_serial(jeu, serial, tirage):
    """Vérifie UN ticket (jeu + numéro de série) contre l'ensemble des boules tirées.
    Renvoie {serial, trouve, [complet, sortis, total, manquants, jeu] | msg}."""
    cle = _variante_cle(jeu)
    ss = _serie_start_pour(jeu, serial)
    if ss is None:
        return {"serial": serial, "trouve": False, "msg": "Lot introuvable pour ce numéro"}
    cellules = None   # jeux "boule pour N" : liste de (lettre, [numeros])
    nums = None       # jeux "une boule" : liste de numeros
    nom = jeu
    if cle == "OHANAORIG":
        cellules = _ohana_cellules(ss, serial); nom = "OHANA 75 (carte 24)"
    elif cle == "OHANA10":
        cellules = _ohana10b_lignes(ss, serial); nom = "OHANA 75 10 boules"
    elif cle == "OHANA8":
        cellules = _ohana8b_lignes(ss, serial); nom = "OHANA 75 8 boules"
    elif cle == "TA75":
        cellules = _ta75_groupes(ss, serial); nom = "TRIPLE ACTION 75"
    elif cle == "P6":
        nums = _p6_numeros(ss, serial); nom = "P6"
    elif cle in _JEUX_PLATS:
        nums = _regen_plat(cle, ss, serial)
        nom = {"DOLLAR": "1 dollar", "F500": "500 francs", "B40": "40 boules", "B60": "60 boules"}.get(cle, jeu)
    elif cle == "4COIN":
        nums = _regen_4coin(ss, serial); nom = "4 COIN"
    elif cle == "ALOHA75":
        nums = _regen_aloha75(ss, serial); nom = "ALOHA 75"
    elif cle == "BINGOBALL":
        nums = _regen_bingoball(ss, serial); nom = "BINGO BALL"
    elif cle == "BROWN8":
        nums = _regen_brown8(ss, serial); nom = "BROWN 8 BOULES"
    elif cle == "KAIB":
        nums = _regen_kai(ss, serial); nom = "KAI"
    elif cle == "FLASHQ":
        nums = _regen_flashq(ss, serial); nom = "FLASH QUINES ALLONGER"
    else:
        return {"serial": serial, "trouve": False, "msg": "Jeu non encore pris en charge"}
    if cellules is not None:
        if not cellules:
            return {"serial": serial, "trouve": False, "msg": "Recalcul impossible"}
        manquants = [f"{l}:{'/'.join(str(n) for n in ns)}" for (l, ns) in cellules
                     if not any(n in tirage for n in ns)]
        total = len(cellules)
        return {"serial": serial, "trouve": True, "jeu": nom,
                "complet": len(manquants) == 0, "sortis": total - len(manquants),
                "total": total, "manquants": manquants}
    if not nums:
        return {"serial": serial, "trouve": False, "msg": "Recalcul impossible"}
    manquants_n = sorted([n for n in nums if n not in tirage])
    return {"serial": serial, "trouve": True, "jeu": nom,
            "complet": len(manquants_n) == 0, "sortis": len(nums) - len(manquants_n),
            "total": len(nums), "manquants": [str(n) for n in manquants_n], "numeros": sorted(nums)}

@app.route("/api/bingo/verifier-carton", methods=["POST"])
def verifier_carton():
    """Vérifie automatiquement si un (ou plusieurs) ticket P6 a son CARTON PLEIN.
    Entrée : {jeu, serial} ou {jeu, serials:[...]}. Réservé Admin/Organisateur."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        # Page de test (lecture seule) : accepter aussi un code organisateur/admin valide
        code_h = (token or "").upper().strip()
        if code_h and code_h in DB.get("codes", {}):
            s = {"code": code_h, "admin": bool(DB["codes"][code_h].get("admin"))}
        else:
            return jsonify({"ok": False, "msg": "Code organisateur non reconnu"}), 403
    d = request.json or {}
    jeu = (d.get("jeu") or "P6").strip()
    serials = d.get("serials")
    if not serials:
        un = d.get("serial")
        serials = [un] if un not in (None, "") else []
    try:
        serials = [int(str(x).strip().lstrip("Ss")) for x in serials if str(x).strip()]
    except Exception:
        return jsonify({"ok": False, "msg": "Numéro de série invalide"}), 400

    tirage = set()
    for x in DB.get("tirage", []):
        try:
            tirage.add(int(x))
        except Exception:
            pass

    resultats = [_verifier_serial(jeu, serial, tirage) for serial in serials]
    gagnant = any(r.get("complet") for r in resultats)
    return jsonify({"ok": True, "gagnant": gagnant, "boules_tirees": len(tirage), "resultats": resultats})

def _structure_carton(jeu, serial):
    """Renvoie les GROUPES (cases) d'une carte : liste de listes de numéros.
    'une boule' -> chaque numéro seul [[n],...] ; 'boule pour 2/3' -> cases [[a,b],...]."""
    cle = _variante_cle(jeu)
    ss = _serie_start_pour(jeu, serial)
    if ss is None:
        return None
    if cle == "OHANAORIG":
        c = _ohana_cellules(ss, serial)
        return [list(ns) for (l, ns) in c] if c else None
    if cle == "OHANA10":
        c = _ohana10b_lignes(ss, serial)
        return [list(ns) for (l, ns) in c] if c else None
    if cle == "OHANA8":
        c = _ohana8b_lignes(ss, serial)
        return [list(ns) for (l, ns) in c] if c else None
    if cle == "TA75":
        c = _ta75_groupes(ss, serial)
        return [list(ns) for (l, ns) in c] if c else None
    if cle == "P6":
        n = _p6_numeros(ss, serial)
        return [[x] for x in n] if n else None
    if cle in _JEUX_PLATS:
        n = _regen_plat(cle, ss, serial)
        return [[x] for x in n] if n else None
    if cle == "4COIN":
        n = _regen_4coin(ss, serial)
        return [[x] for x in n] if n else None
    if cle == "ALOHA75":
        n = _regen_aloha75(ss, serial)
        return [[x] for x in n] if n else None
    if cle == "BINGOBALL":
        n = _regen_bingoball(ss, serial)
        return [[x] for x in n] if n else None
    if cle == "BROWN8":
        n = _regen_brown8(ss, serial)
        return [[x] for x in n] if n else None
    if cle == "KAIB":
        n = _regen_kai(ss, serial)
        return [[x] for x in n] if n else None
    if cle == "FLASHQ":
        n = _regen_flashq(ss, serial)
        return [[x] for x in n] if n else None
    return None

@app.route("/api/bingo/structure-carton", methods=["POST"])
def structure_carton():
    """Donne au joueur la structure de sa/ses carte(s) pour le pointage automatique
    (quels numéros forment une même case → 'une boule pour 2/3'). Lecture seule."""
    global DB
    DB = load_data()
    d = request.json or {}
    jeu = (d.get("jeu") or "").strip()
    serials = d.get("serials")
    if not serials:
        un = d.get("serial")
        serials = [un] if un not in (None, "") else []
    out = {}
    for sx in serials:
        try:
            si = int(str(sx).strip().lstrip("Ss"))
        except Exception:
            continue
        g = _structure_carton(jeu, si)
        if g is not None:
            out[str(si)] = g
    return jsonify({"ok": True, "structures": out})

