@app.route("/diag-ecarts")
def diag_ecarts():
    """Réconciliation des GAINS : pour chaque gagnant, compare ce qu'il devrait
    avoir (relevé) et son solde réel. Liste qui reste à recréditer. ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    pj_all = DB.get("pions_joueurs", {})

    def solde_reel(code):
        p = pj_all.get(code, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10

    # Décompose un manquant en pions recréditables (100/50/20). Le reliquat
    # éventuel de 10 XPF n'est pas recréditable par l'outil (qui gère 100/50/20).
    def deco(montant):
        m = max(0, int(montant))
        n100 = m // 100; m -= n100*100
        n50 = m // 50; m -= n50*50
        n20 = m // 20; m -= n20*20
        bouts = []
        if n100: bouts.append(f"{n100}×100")
        if n50: bouts.append(f"{n50}×50")
        if n20: bouts.append(f"{n20}×20")
        txt = " + ".join(bouts) if bouts else "—"
        if m > 0:
            txt += f" (+{m} XPF en espèces)"
        return txt

    # Calcule entrées/sorties pour un joueur — MÊME comptabilité que le relevé,
    # pour rester juste après les recrédits admin.
    def attendu_pour(code):
        ent = 0; sor = 0
        for c in DB.get("commandes_pions_joueurs", []):
            if isinstance(c, dict) and c.get("code_joueur") == code and c.get("statut") == "validee":
                nb = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0)
                val = int(c.get("valeur_pion", 0) or 0)
                v = nb * val
                if v <= 0:
                    v = int(c.get("montant_net", 0) or 0)
                ent += v
        for t in DB.get("transactions_joueur_org", []):
            if isinstance(t, dict) and t.get("code_joueur") == code:
                ent += int(t.get("montant_total", 0) or 0)
        for g in DB.get("gains_finaux", []):
            if isinstance(g, dict) and g.get("code_gagnant") == code and not g.get("annule"):
                ent += int(g.get("montant_credite", 0) or 0)
        # NB : les crédits admin (re-crédits de réconciliation) ne comptent PAS
        # comme une attente : ils servent à COMBLER un trou (ils montent le solde
        # réel pour rejoindre l'attendu). Sinon la ligne ne se refermerait jamais.
        # On ne garde que les DÉBITS admin (retraits volontaires), qui eux baissent
        # le solde réel et doivent donc baisser l'attendu.
        for c in DB.get("credits_admin", []):
            if isinstance(c, dict) and c.get("code_joueur") == code:
                m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
                if m < 0:
                    sor += -m
        for rb in DB.get("remboursements_tournoi", []):
            if isinstance(rb, dict):
                for det in (rb.get("detail") or []):
                    if isinstance(det, dict) and det.get("code_joueur") == code:
                        ent += int(det.get("montant", 0) or 0)
        for c in DB.get("commandes_tickets_pions", []):
            if isinstance(c, dict) and c.get("code_joueur") == code:
                sor += int(c.get("total_pions", 0) or 0)
        for r in DB.get("demandes_retrait", []):
            if isinstance(r, dict) and r.get("code_joueur") == code and r.get("statut") == "validee":
                sor += int(r.get("montant_demande", 0) or 0)
        for c in DB.get("corrections_pions", []):
            if isinstance(c, dict) and c.get("code_joueur") == code:
                ret = int(c.get("solde_avant", 0) or 0) - int(c.get("solde_apres", 0) or 0)
                if ret > 0: sor += ret
        # Gains PAYÉS au gagnant (virement / espèces chez l'admin) = sortie :
        # son gain a déjà été versé, ce n'est plus dû en pions.
        for v in DB.get("virements_gagnants", []):
            if isinstance(v, dict) and (v.get("gagnant") or "").upper().strip() == code:
                sor += int(v.get("montant", 0) or 0)
        return ent - sor

    # Détail lisible des mouvements d'une joueuse (pour juger un écart)
    def detail_pour(code):
        gain = sum(int(g.get("montant_credite", 0) or 0) for g in DB.get("gains_finaux", [])
                   if isinstance(g, dict) and g.get("code_gagnant") == code and not g.get("annule"))
        achats = 0
        for c in DB.get("commandes_pions_joueurs", []):
            if isinstance(c, dict) and c.get("code_joueur") == code and c.get("statut") == "validee":
                nb = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0)
                val = int(c.get("valeur_pion", 0) or 0)
                v = nb * val
                if v <= 0:
                    v = int(c.get("montant_net", 0) or 0)
                achats += v
        recus = sum(int(t.get("montant_total", 0) or 0) for t in DB.get("transactions_joueur_org", [])
                    if isinstance(t, dict) and t.get("code_joueur") == code)
        remb = sum(int(det.get("montant", 0) or 0) for rb in DB.get("remboursements_tournoi", []) if isinstance(rb, dict)
                   for det in (rb.get("detail") or []) if isinstance(det, dict) and det.get("code_joueur") == code)
        tickets = sum(int(c.get("total_pions", 0) or 0) for c in DB.get("commandes_tickets_pions", [])
                      if isinstance(c, dict) and c.get("code_joueur") == code)
        retraits = sum(int(r.get("montant_demande", 0) or 0) for r in DB.get("demandes_retrait", [])
                       if isinstance(r, dict) and r.get("code_joueur") == code and r.get("statut") == "validee")
        corr = 0
        for c in DB.get("corrections_pions", []):
            if isinstance(c, dict) and c.get("code_joueur") == code:
                ret = int(c.get("solde_avant", 0) or 0) - int(c.get("solde_apres", 0) or 0)
                if ret > 0:
                    corr += ret
        recred = sum(int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0) for c in DB.get("credits_admin", [])
                     if isinstance(c, dict) and c.get("code_joueur") == code and (int(c.get("nb_pions", 0) or 0) > 0))
        virem = sum(int(v.get("montant", 0) or 0) for v in DB.get("virements_gagnants", [])
                    if isinstance(v, dict) and (v.get("gagnant") or "").upper().strip() == code)
        bits = []
        if gain: bits.append(f"gain {gain}")
        if achats: bits.append(f"achats {achats}")
        if recus: bits.append(f"reçus org {recus}")
        if remb: bits.append(f"remb. {remb}")
        if tickets: bits.append(f"tickets −{tickets}")
        if retraits: bits.append(f"retraits −{retraits}")
        if virem: bits.append(f"virement gagnant −{virem}")
        if corr: bits.append(f"corrections −{corr}")
        if recred: bits.append(f"déjà recrédité {recred}")
        bits.append(f"<b style='color:#cbd5e1'>solde réel {solde_reel(code)}</b>")
        return " · ".join(bits)
    # Ce ne sont PAS des joueuses -> on les exclut de la réconciliation.
    codes_non_joueurs = set((k or "").upper().strip() for k in DB.get("codes", {}).keys())

    # Codes ayant reçu un GAIN enregistré (signature d'une vraie perte si non reflété)
    codes_avec_gain = set()
    for g in DB.get("gains_finaux", []):
        cg = (g.get("code_gagnant") or "").upper().strip()
        if cg:
            codes_avec_gain.add(cg)

    # Tous les codes JOUEUSES à analyser : gagnantes + tout solde de pions
    codes = set()
    for cg in codes_avec_gain:
        codes.add(cg)
    for k in pj_all.keys():
        if k:
            codes.add(k.upper().strip() if isinstance(k, str) else k)

    # --- Détection des codes en DOUBLE (O/0, I/1, emoji, espaces) ---
    def _norm(c):
        s = "".join(ch for ch in str(c).upper() if ch.isalnum())
        return s.replace("O", "0").replace("I", "1")
    groupes = {}
    for c in codes:
        groupes.setdefault(_norm(c), []).append(c)
    doublons = [sorted(v) for v in groupes.values() if len(set(v)) > 1]

    prio = []        # vraie perte de gain (a un gain enregistré, solde en dessous)
    a_verifier = []  # écart négatif sans gain (peut être un vieux solde)
    en_trop = 0      # nombre de "en trop" (jamais une dette)
    impossibles = 0  # attendu < 0 (journal incomplet)
    suspects_fraude = []  # codes ayant émis des transferts ou bloqués -> NE PAS recréditer

    # Codes ayant ENVOYÉ des transferts (hors admin) = manipulation possible
    codes_emetteurs = set()
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and not t.get("admin") and t.get("de"):
            codes_emetteurs.add((t.get("de") or "").upper())
    codes_bloques_set = set(DB.get("codes_bloques", []))

    for code in codes:
        if code in codes_non_joueurs:
            continue  # organisateur / admin -> ignoré
        attendu = attendu_pour(code)
        reel = solde_reel(code)
        ecart = reel - attendu
        if ecart >= 0:
            if ecart > 0:
                en_trop += 1
            continue
        if attendu < 0:
            impossibles += 1
            continue  # cas impossible -> journal incomplet, pas fiable
        ligne = (code, reel, attendu, -ecart)
        # PROTECTION ANTI-FRAUDE : un code qui a transféré des pions ou qui est
        # bloqué n'est JAMAIS proposé au recrédit (piège des faux écarts).
        if code in codes_emetteurs or code in codes_bloques_set:
            suspects_fraude.append(ligne)
            continue
        if code in codes_avec_gain:
            prio.append(ligne)
        else:
            a_verifier.append(ligne)

    prio.sort(key=lambda r: -r[3])
    a_verifier.sort(key=lambda r: -r[3])
    suspects_fraude.sort(key=lambda r: -r[3])

    def _tr(r, accent):
        code, reel, attendu, du = r
        return (f'<tr><td style="padding:8px 8px 1px;font-family:monospace;color:#a78bfa">{code}</td>'
                f'<td style="padding:8px 8px 1px;color:#94a3b8">a {reel} / devrait {attendu}</td>'
                f'<td style="padding:8px 8px 1px;color:{accent};font-weight:600">doit {du} XPF → {deco(du)}</td></tr>'
                f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)"><td colspan="3" style="padding:0 8px 8px;color:#6b7280;font-size:11px">détail : {detail_pour(code)}</td></tr>')

    corps_prio = "".join(_tr(r, "#fca5a5") for r in prio) or '<tr><td colspan="3" style="padding:10px;color:#6ee7b7">Aucune perte de gain détectée. ✅</td></tr>'
    corps_verif = "".join(_tr(r, "#fbbf24") for r in a_verifier) or '<tr><td colspan="3" style="padding:10px;color:#6ee7b7">Rien à vérifier. ✅</td></tr>'
    corps_suspects = "".join(_tr(r, "#f87171") for r in suspects_fraude)
    bloc_suspects = ""
    if suspects_fraude:
        bloc_suspects = (f'<div style="background:rgba(239,68,68,.12);border:2px solid #ef4444;border-radius:10px;padding:12px;margin-bottom:16px">'
                         f'<div style="color:#fca5a5;font-weight:800;margin-bottom:8px">🚨 Écarts SUSPECTS — NE PAS recréditer ({len(suspects_fraude)})</div>'
                         f'<div style="color:#fca5a5;font-size:12px;margin-bottom:8px">Ces codes ont <b>envoyé des transferts</b> ou sont <b>bloqués</b> : leur « écart » est presque sûrement de la <b>fraude</b> (faux écart créé en faisant tourner des pions). Les recréditer reviendrait à fabriquer de la valeur pour le fraudeur. Vérifie-les dans <b>/audit-fraude</b>.</div>'
                         f'<table style="width:100%;border-collapse:collapse;font-size:13px">{corps_suspects}</table></div>')

    total_prio = sum(r[3] for r in prio)
    bloc_doublons = ""
    if doublons:
        items = "".join(f'<li style="margin:4px 0;font-family:monospace;color:#fde68a">{" = ".join(g)}</li>' for g in doublons)
        bloc_doublons = (f'<div style="margin-top:18px;background:rgba(251,191,36,.08);border:1px solid #f59e0b;border-radius:10px;padding:12px">'
                         f'<div style="color:#fbbf24;font-weight:700;margin-bottom:6px">🔁 Codes très similaires — peut-être la MÊME joueuse</div>'
                         f'<ul style="margin:0;padding-left:18px;font-size:13px">{items}</ul>'
                         f'<div style="color:#94a3b8;font-size:12px;margin-top:6px">Vérifie : ses pions sont peut-être sur un code et son gain sur l\'autre. Ne la recrédite qu\'UNE fois.</div></div>')

    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Réconciliation des soldes</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:820px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7">🧮 Réconciliation des soldes</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:16px">Joueuses seulement (organisateurs exclus). Les « soldes en trop » ne sont <b>jamais</b> une dette.</div>

      <div style="background:rgba(252,165,165,.07);border:1px solid #ef4444;border-radius:10px;padding:12px;margin-bottom:16px">
        <div style="color:#fca5a5;font-weight:700;margin-bottom:8px">🔴 Pertes de gain confirmées — à recréditer en priorité ({len(prio)} · {total_prio} XPF)</div>
        <table style="width:100%;border-collapse:collapse;font-size:13px">{corps_prio}</table>
      </div>

      <div style="background:rgba(251,191,36,.06);border:1px solid #f59e0b;border-radius:10px;padding:12px;margin-bottom:16px">
        <div style="color:#fbbf24;font-weight:700;margin-bottom:8px">🟠 Écarts à vérifier au cas par cas ({len(a_verifier)})</div>
        <div style="color:#94a3b8;font-size:12px;margin-bottom:8px">Pas de gain enregistré pour ces codes : ça peut être un <b>vieux solde d'avant le journal</b>. Ne recrédite que si la joueuse réclame et que tu confirmes.</div>
        <table style="width:100%;border-collapse:collapse;font-size:13px">{corps_verif}</table>
      </div>

      {bloc_suspects}

      <div style="color:#6ee7b7;font-size:13px;margin-bottom:6px">🟢 {en_trop} joueuse(s) ont « plus » que le journal ne sait expliquer → <b>aucune dette</b>, rien à faire.</div>
      <div style="color:#94a3b8;font-size:12px">⚪ {impossibles} cas ignorés (journal incomplet, montant impossible).</div>
      {bloc_doublons}

      <div style="margin-top:16px;color:#94a3b8;font-size:12px;line-height:1.5">Pour recréditer : outil admin « Recréditer joueur », avec la décomposition indiquée. Le mouvement est tracé (Crédit admin) et la ligne disparaît d'ici.</div>
    </div></body></html>'''

@app.route("/corriger-double-bonus")
def corriger_double_bonus():
    """ADMIN — Retire le 2e bonus de 500 F chez les inscrites « semaine » qui l'ont
    reçu DEUX fois (cadeau d'inscription + outil petits-jeux). Ne retire que chez
    celles qui ont encore au moins 500 F de bonus (jamais en négatif). Aperçu d'abord."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    confirme = request.args.get("confirme", "") == "1"
    log = DB.get("rejoindre_log", [])
    deja = set(DB.get("bonus_petitsjeux_donne", []))
    semaine = {(x.get("code", "") or "").upper() for x in log
               if (x.get("campagne", "") or "") == "semaine" and x.get("code")}

    def bonus_solde(code):
        pb = DB.get("pions_bonus_joueurs", {}).get(code, {})
        return pb.get("100", 0) * 100 + pb.get("50", 0) * 50 + pb.get("20", 0) * 20 + pb.get("10", 0) * 10

    targets = [c for c in deja if c.upper() in semaine]
    recuperables = [c for c in targets if bonus_solde(c) >= 500]
    entames = [c for c in targets if bonus_solde(c) < 500]

    def page(corps):
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Doublons bonus</title></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:18px;color:#fff">
        <div style="max-width:600px;margin:0 auto">{corps}</div></body></html>''', mimetype="text/html; charset=utf-8")

    if not confirme:
        if not targets:
            return page('<h1 style="color:#34d399;font-size:20px">✅ Aucun doublon</h1><p style="color:#94a3b8">Personne n\'a reçu le bonus « semaine » deux fois. Rien à corriger.</p>')
        url_ok = f"/corriger-double-bonus?cle={cle}&confirme=1"
        return page(f'<h1 style="color:#a855f7;font-size:20px">🔁 Doublons de bonus « semaine »</h1>'
                    f'<div style="background:#161b22;border:1px solid #30363d;border-radius:12px;padding:16px;margin:12px 0;line-height:1.8">'
                    f'Inscrites ayant reçu 500 F <b>deux fois</b> : <b>{len(targets)}</b><br>'
                    f'\u2705 Encore récupérables (bonus \u2265 500) : <b style="color:#34d399">{len(recuperables)}</b> \u2192 on retire 500 F chacune<br>'
                    f'\u26A0\uFE0F Déjà entamées (bonus < 500, jamais en négatif) : <b style="color:#fbbf24">{len(entames)}</b> \u2192 on n\'y touche pas<br>'
                    f'Total à retirer : <b style="color:#fbbf24">{len(recuperables) * 500} F</b> de pions bonus (non retirables \u2014 aucun impact cash)</div>'
                    f'<a href="{url_ok}" style="display:inline-block;background:#ef4444;color:#fff;padding:12px 22px;border-radius:10px;text-decoration:none;font-weight:700">✅ Retirer les doublons</a>'
                    f'<p style="color:#6b7280;font-size:12px;margin-top:10px">Chaque inscrite garde son cadeau d\'inscription (500 F). On retire seulement le 2e crédit en trop.</p>')

    # === EXECUTION ===
    retires = 0
    for code in recuperables:
        poche = DB.setdefault("pions_bonus_joueurs", {}).get(code, {})
        if _debiter_pions_montant(poche, 500):
            DB["pions_bonus_joueurs"][code] = poche
            for cm in DB.get("credits_masse", []):
                if str(cm.get("motif", "")).startswith("Bonus 500F inscription QR") and code in (cm.get("codes") or []):
                    cm["codes"] = [x for x in cm["codes"] if x != code]
            deja.discard(code)
            retires += 1
    DB["bonus_petitsjeux_donne"] = list(deja)
    save_data(immediat=True)
    return page(f'<h1 style="color:#34d399;font-size:20px">✅ Doublons corrigés</h1>'
                f'<p style="color:#fff"><b>{retires}</b> inscrite(s) : le 2e bonus de 500 F a été retiré (elles gardent leur cadeau d\'inscription).</p>'
                f'<p style="color:#94a3b8"><b>{len(entames)}</b> déjà entamées : laissées telles quelles (aucun impact cash, bonus non retirable).</p>'
                f'<p style="margin-top:10px"><a href="/crediter-petits-jeux?cle={cle}" style="color:#a78bfa">← Revenir aux campagnes</a></p>')

@app.route("/crediter-petits-jeux")
def crediter_petits_jeux():
    """ADMIN — Crédite 500 F de pions bonus aux inscrites d'une campagne (ex. QR
    petits jeux) qui ne l'ont pas déjà reçu. Idempotent.
    ?cle=ADMIN  -> liste les campagnes. &campagne=X -> aperçu. &confirme=1 -> crédite."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    log = DB.get("rejoindre_log", [])
    deja = set(DB.get("bonus_petitsjeux_donne", []))
    campagne = (request.args.get("campagne", "") or "").strip()
    confirme = request.args.get("confirme", "") == "1"

    def page(corps):
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Crédit petits jeux</title></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:18px;color:#fff">
        <div style="max-width:620px;margin:0 auto">{corps}</div></body></html>''', mimetype="text/html; charset=utf-8")

    # --- LISTE DES CAMPAGNES ---
    if not campagne:
        stats = {}
        for x in log:
            c = (x.get("campagne", "") or "(sans campagne)")
            code = x.get("code")
            d = stats.setdefault(c, {"total": set(), "credit": set()})
            if code:
                d["total"].add(code)
                if code in deja:
                    d["credit"].add(code)
        if not stats:
            return page('<h1 style="color:#a855f7;font-size:20px">📲 Inscriptions QR</h1><p style="color:#94a3b8">Aucune inscription enregistrée pour le moment.</p>')
        lignes = ""
        for c, d in sorted(stats.items(), key=lambda kv: -len(kv[1]["total"])):
            tot = len(d["total"]); cre = len(d["credit"]); reste = tot - cre
            url = f"/crediter-petits-jeux?cle={cle}&campagne={c}"
            lignes += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
                       f'<td style="padding:10px;font-weight:600">{c}</td>'
                       f'<td style="padding:10px;color:#94a3b8">{tot} inscrites · {cre} déjà créditées</td>'
                       f'<td style="padding:10px">{"<a href=\'" + url + "\' style=\'color:#34d399;font-weight:700\'>Créditer " + str(reste) + " →</a>" if reste > 0 else "<span style=\'color:#6ee7b7\'>✅ à jour</span>"}</td></tr>')
        return page(f'<h1 style="color:#a855f7;font-size:20px">📲 Inscriptions par QR / campagne</h1>'
                    f'<p style="color:#94a3b8;font-size:13px">Choisis la campagne du QR « petits jeux » pour créditer 500 F de pions bonus aux inscrites qui ne l\'ont pas reçu.</p>'
                    f'<table style="width:100%;border-collapse:collapse;font-size:14px;margin-top:10px">{lignes}</table>')

    # --- CIBLES D'UNE CAMPAGNE ---
    cibles = []
    for x in log:
        c = (x.get("campagne", "") or "(sans campagne)")
        if c == campagne and x.get("code"):
            if x["code"] not in cibles:
                cibles.append(x["code"])
    a_crediter = [c for c in cibles if c not in deja]

    if not confirme:
        url_ok = f"/crediter-petits-jeux?cle={cle}&campagne={campagne}&confirme=1"
        avert = ('<div style="background:rgba(251,191,36,.12);border:1px solid #f59e0b;border-radius:10px;padding:12px;margin:10px 0;color:#fcd34d;font-size:14px">\u26A0\uFE0F La campagne « semaine » donne <b>déjà 500 F à l\'inscription</b>. Créditer ici <b>doublerait</b> le bonus. À éviter sauf si tu es sûre qu\'elles ne l\'ont pas reçu.</div>' if campagne == "semaine" else '')
        return page(f'<h1 style="color:#a855f7;font-size:20px">Aperçu — campagne « {campagne} »</h1>{avert}'
                    f'<div style="background:#161b22;border:1px solid #30363d;border-radius:12px;padding:16px;margin:12px 0;line-height:1.8">'
                    f'Inscrites : <b>{len(cibles)}</b><br>'
                    f'Déjà créditées : <b>{len(cibles) - len(a_crediter)}</b><br>'
                    f'À créditer maintenant (500 F bonus chacune) : <b style="color:#34d399">{len(a_crediter)}</b><br>'
                    f'Total à distribuer : <b style="color:#fbbf24">{len(a_crediter) * 500} F</b></div>'
                    + (f'<a href="{url_ok}" style="display:inline-block;background:#059669;color:#fff;padding:12px 22px;border-radius:10px;text-decoration:none;font-weight:700">✅ Créditer les {len(a_crediter)} maintenant</a>'
                       if a_crediter else '<p style="color:#6ee7b7">✅ Tout le monde a déjà reçu son bonus.</p>')
                    + '<p style="color:#6b7280;font-size:12px;margin-top:10px">Les 500 F sont des pions BONUS (jouables, non retirables), comme à l\'inscription.</p>')

    # --- EXECUTION ---
    faits = 0
    for code in a_crediter:
        poche = DB.setdefault("pions_bonus_joueurs", {}).get(code, {})
        _crediter_pions_montant(poche, 500)
        DB["pions_bonus_joueurs"][code] = poche
        deja.add(code)
        faits += 1
    DB["bonus_petitsjeux_donne"] = list(deja)
    DB.setdefault("credits_masse", []).insert(0, {
        "profil": "joueur", "codes": a_crediter, "nb_pions": 5, "valeur_pion": 100,
        "motif": f"Bonus 500F inscription QR ({campagne})", "bonus": True,
        "par": cle, "date": datetime.datetime.now().isoformat()
    })
    save_data(immediat=True)
    return page(f'<h1 style="color:#34d399;font-size:20px">✅ Crédit effectué</h1>'
                f'<p style="color:#fff"><b>{faits}</b> joueuse(s) de la campagne « {campagne} » ont reçu <b>500 F de pions bonus</b>.</p>'
                f'<p style="color:#94a3b8">Total distribué : <b style="color:#fbbf24">{faits * 500} F</b>. Tu peux relancer ce lien sans risque : personne ne sera crédité deux fois.</p>'
                f'<p style="margin-top:10px"><a href="/crediter-petits-jeux?cle={cle}" style="color:#a78bfa">← Revoir les campagnes</a></p>')

@app.route("/maj-tournoi-juillet")
def maj_tournoi_juillet():
    """ADMIN — Reporte le tournoi au vendredi 3 juillet 2026 ET publie l'annonce
    aux joueuses, en un clic. ?cle=ADMIN[&heure=HH:MM][&nom=...][&jeu=...]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    heure = (request.args.get("heure", "") or "19:00").strip()
    if len(heure) == 5 and heure[2] == ":" and heure.replace(":", "").isdigit():
        pass
    else:
        heure = "19:00"
    nom = (request.args.get("nom", "") or "Grand tournoi TUKEA").strip()
    jeu = (request.args.get("jeu", "") or "").strip()
    date_heure = "2026-07-03T" + heure

    # 1) Retirer l'ancien tournoi d'aujourd'hui (26/06/2026) s'il existe
    avant = DB.get("tournois_programmes", [])
    DB["tournois_programmes"] = [t for t in avant
                                 if not str(t.get("date_heure", "")).startswith("2026-06-26")]
    retires = len(avant) - len(DB["tournois_programmes"])

    # 2) Programmer le tournoi du 3 juillet
    tournoi = {
        "id": secrets.token_hex(4).upper(),
        "code_org": cle,
        "nom_org": info.get("nom", "TUKEA"),
        "nom": nom,
        "jeu": jeu,
        "date_heure": date_heure,
        "created": datetime.datetime.now().isoformat()
    }
    DB["tournois_programmes"].insert(0, tournoi)

    # 3) Publier l'annonce en bandeau chez toutes les joueuses
    texte = ("\U0001F3B2 Le tournoi est report\u00e9 \u00e0 vendredi 3 juillet 2026. "
             "Vos pions et vos tickets restent valables \u2014 rien n'est perdu ! "
             "Prenez vos tickets d\u00e8s maintenant pour \u00eatre pr\u00eates. \u00c0 tr\u00e8s vite ! \U0001F33A TUKEA")
    DB["message_joueurs"] = {"actif": True, "texte": texte,
                             "date": datetime.datetime.now().isoformat(), "par": cle}

    save_data(immediat=True)
    h_aff = heure.replace(":", "h")
    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Report tournoi</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:18px;color:#fff">
    <div style="max-width:560px;margin:0 auto">
      <h1 style="color:#34d399;font-size:20px">\u2705 Report effectu\u00e9 !</h1>
      <div style="background:#161b22;border:1px solid #30363d;border-radius:12px;padding:16px;margin-top:12px;line-height:1.7">
        \U0001F4C5 Tournoi programm\u00e9 : <b>{nom}</b><br>
        \U0001F5D3\uFE0F Date : <b style="color:#fbbf24">vendredi 3 juillet 2026 \u00e0 {h_aff}</b>{(' \u00b7 ' + jeu) if jeu else ''}<br>
        \U0001F4E2 Annonce publi\u00e9e \u00e0 toutes les joueuses (bandeau)<br>
        \U0001F9F9 Ancien tournoi d'aujourd'hui retir\u00e9 : <b>{retires}</b>
      </div>
      <p style="color:#8b949e;font-size:13px;margin-top:12px">Tes joueuses voient maintenant le compte \u00e0 rebours vers le 3 juillet et le message d'annonce.</p>
      <p style="color:#8b949e;font-size:12px">Heure diff\u00e9rente ? Rappelle ce lien avec <code style="color:#a78bfa">&heure=20:00</code> par exemple.</p>
    </div></body></html>''', mimetype="text/html; charset=utf-8")

@app.route("/fusion-codes")
def fusion_codes():
    """ADMIN — Fusionne un code FANTÔME (de) dans le VRAI code (vers) :
    déplace les pions et rattache tous les mouvements. Aperçu d'abord ;
    rien n'est modifié sans &confirme=1.
    Usage : /fusion-codes?cle=ADMIN&de=CODE_FANTOME&vers=CODE_REEL[&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    de = (request.args.get("de", "") or "").strip()
    vers = (request.args.get("vers", "") or "").strip()
    confirme = request.args.get("confirme", "") == "1"

    def page(msg):
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Fusion de codes</title></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
        <div style="max-width:720px;margin:0 auto">{msg}</div></body></html>''', mimetype="text/html; charset=utf-8")

    if not de or not vers:
        return page('<h1 style="color:#a855f7;font-size:20px">🔁 Fusion de codes</h1>'
                    '<p style="color:#94a3b8">Ajoute à l\'adresse : <code style="color:#fde68a">&de=CODE_FANTOME&vers=CODE_REEL</code></p>'
                    '<p style="color:#94a3b8;font-size:13px">Le code <b>vers</b> doit être celui où la joueuse <b>peut se connecter</b>.</p>')

    if de == vers:
        return page('<p style="color:#fca5a5">Les deux codes sont identiques.</p>')

    def solde(code):
        p = DB.get("pions_joueurs", {}).get(code, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10

    acces_de = de in DB.get("tickets_acheteurs", {})
    acces_vers = vers in DB.get("tickets_acheteurs", {})

    # Recense ce qui sera rattaché (par champ code_joueur / code_gagnant / gagnant / codes)
    plans = []
    def compte_cj(cle_db):
        return sum(1 for x in DB.get(cle_db, []) if isinstance(x, dict) and x.get("code_joueur") == de)
    for k in ["commandes_pions_joueurs", "commandes_tickets_pions", "transactions_joueur_org",
              "demandes_retrait", "corrections_pions", "credits_admin"]:
        n = compte_cj(k)
        if n: plans.append((k, n))
    n_gains = sum(1 for g in DB.get("gains_finaux", []) if isinstance(g, dict) and g.get("code_gagnant") == de)
    if n_gains: plans.append(("gains_finaux", n_gains))
    n_vir = sum(1 for v in DB.get("virements_gagnants", []) if isinstance(v, dict) and (v.get("gagnant") or "") == de)
    if n_vir: plans.append(("virements_gagnants", n_vir))
    n_remb = sum(1 for rb in DB.get("remboursements_tournoi", []) if isinstance(rb, dict)
                 for det in (rb.get("detail") or []) if isinstance(det, dict) and det.get("code_joueur") == de)
    if n_remb: plans.append(("remboursements_tournoi", n_remb))
    n_masse = sum(1 for c in DB.get("credits_masse", []) if isinstance(c, dict) and de in (c.get("codes") or []))
    if n_masse: plans.append(("credits_masse", n_masse))

    badge = lambda ok: ('<span style="color:#6ee7b7">✅ accès</span>' if ok else '<span style="color:#fca5a5">❌ pas d\'accès</span>')
    recap = (f'<table style="width:100%;border-collapse:collapse;font-size:14px;margin:12px 0">'
             f'<tr style="border-bottom:1px solid #333"><td style="padding:8px;color:#94a3b8">FANTÔME (source)</td>'
             f'<td style="padding:8px;font-family:monospace;color:#fca5a5">{de}</td><td style="padding:8px">{solde(de)} XPF · {badge(acces_de)}</td></tr>'
             f'<tr><td style="padding:8px;color:#94a3b8">VRAI (destination)</td>'
             f'<td style="padding:8px;font-family:monospace;color:#6ee7b7">{vers}</td><td style="padding:8px">{solde(vers)} XPF · {badge(acces_vers)}</td></tr></table>')
    liste = "".join(f'<li style="margin:3px 0"><b>{n}</b> dans <code style="color:#a78bfa">{k}</code></li>' for k, n in plans) or '<li style="color:#94a3b8">aucun mouvement à rattacher</li>'

    if not confirme:
        avert = ""
        if not acces_vers:
            avert = '<div style="background:rgba(252,165,165,.1);border:1px solid #ef4444;border-radius:8px;padding:10px;margin:10px 0;color:#fca5a5">⚠️ Le code destination n\'a PAS d\'accès. Vérifie que c\'est bien le bon sens (vers = celui où elle se connecte).</div>'
        url_ok = f"/fusion-codes?cle={cle}&de={de}&vers={vers}&confirme=1"
        return page(f'<h1 style="color:#a855f7;font-size:20px">🔁 Aperçu de la fusion</h1>{recap}{avert}'
                    f'<div style="color:#fff;margin-top:10px">Vont être déplacés de <code style="color:#fca5a5">{de}</code> vers <code style="color:#6ee7b7">{vers}</code> :</div>'
                    f'<ul style="font-size:13px;color:#fff">{liste}</ul>'
                    f'<div style="color:#94a3b8;font-size:13px;margin:10px 0">Solde final de <b>{vers}</b> : <b style="color:#6ee7b7">{solde(de)+solde(vers)} XPF</b>. Le code {de} sera vidé.</div>'
                    f'<a href="{url_ok}" style="display:inline-block;margin-top:8px;background:#ef4444;color:#fff;padding:12px 20px;border-radius:10px;text-decoration:none;font-weight:700">✅ Confirmer la fusion</a>'
                    f'<div style="color:#6b7280;font-size:12px;margin-top:8px">Action tracée. Rien n\'est supprimé, tout est rattaché.</div>')

    # === EXECUTION ===
    pj = DB.setdefault("pions_joueurs", {})
    src = pj.get(de, {})
    dst = pj.setdefault(vers, {})
    for v in ["100", "50", "20", "10"]:
        if src.get(v):
            dst[v] = dst.get(v, 0) + src.get(v, 0)
    pjb = DB.setdefault("pions_bonus_joueurs", {})
    if de in pjb:
        b = pjb.get(de, {})
        db_ = pjb.setdefault(vers, {})
        for v in ["100", "50", "20", "10"]:
            if b.get(v):
                db_[v] = db_.get(v, 0) + b.get(v, 0)
        pjb.pop(de, None)
    if de in pj:
        pj.pop(de, None)

    deplaces = 0
    for k in ["commandes_pions_joueurs", "commandes_tickets_pions", "transactions_joueur_org",
              "demandes_retrait", "corrections_pions", "credits_admin"]:
        for x in DB.get(k, []):
            if isinstance(x, dict) and x.get("code_joueur") == de:
                x["code_joueur"] = vers; deplaces += 1
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and g.get("code_gagnant") == de:
            g["code_gagnant"] = vers; deplaces += 1
    for v in DB.get("virements_gagnants", []):
        if isinstance(v, dict) and (v.get("gagnant") or "") == de:
            v["gagnant"] = vers; deplaces += 1
    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict):
            for det in (rb.get("detail") or []):
                if isinstance(det, dict) and det.get("code_joueur") == de:
                    det["code_joueur"] = vers; deplaces += 1
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict) and de in (c.get("codes") or []):
            c["codes"] = [vers if x == de else x for x in c["codes"]]; deplaces += 1
    # Le code fantôme cesse d'exister (registre d'accès)
    if de in DB.get("tickets_acheteurs", {}):
        DB["tickets_acheteurs"].pop(de, None)

    DB.setdefault("fusions_codes", []).insert(0, {
        "de": de, "vers": vers, "mouvements_deplaces": deplaces,
        "par": cle, "date": datetime.datetime.now().isoformat()
    })
    save_data(immediat=True)
    return page(f'<h1 style="color:#6ee7b7;font-size:20px">✅ Fusion effectuée</h1>'
                f'<p style="color:#fff">Tout a été déplacé de <code style="color:#fca5a5">{de}</code> vers <code style="color:#6ee7b7">{vers}</code>.</p>'
                f'<p style="color:#94a3b8">Solde de <b>{vers}</b> : <b style="color:#6ee7b7">{solde(vers)} XPF</b> · {deplaces} mouvement(s) rattaché(s).</p>'
                f'<p style="margin-top:10px"><a href="/diag-ecarts?cle={cle}" style="color:#a78bfa">← Revoir la réconciliation</a></p>')

@app.route("/transfert-pions")
def transfert_pions_admin():
    """ADMIN UNIQUEMENT — Transfère des pions réels d'un code vers un autre.
    Réservé à l'admin (les joueuses ne peuvent plus transférer entre elles).
    ?cle=ADMIN&de=CODE&vers=CODE&montant=N[&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    de = (request.args.get("de", "") or "").strip().upper()
    vers = (request.args.get("vers", "") or "").strip().upper()
    try:
        montant = int(request.args.get("montant", 0) or 0)
    except Exception:
        montant = 0
    confirme = request.args.get("confirme", "") == "1"

    def page(corps):
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Transfert admin</title></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:18px;color:#fff">
        <div style="max-width:560px;margin:0 auto">{corps}</div></body></html>''', mimetype="text/html; charset=utf-8")

    if not de or not vers or montant <= 0:
        return page('<h1 style="color:#a855f7;font-size:20px">🔁 Transfert de pions (admin)</h1>'
                    '<p style="color:#94a3b8">Complète l\'adresse ainsi :</p>'
                    '<p style="color:#fde68a;font-family:monospace;font-size:13px;word-break:break-all">…/transfert-pions?cle=TON_CODE&de=CODE_SOURCE&vers=CODE_CIBLE&montant=500</p>'
                    '<p style="color:#94a3b8;font-size:13px">Le montant doit être un multiple de 10. Seul toi (admin) peux faire ce transfert.</p>')

    if de == vers:
        return page('<p style="color:#fca5a5">Le code source et le code cible sont identiques.</p>')
    if montant % 10 != 0:
        return page('<p style="color:#fca5a5">Le montant doit être un multiple de 10 XPF.</p>')

    pj = DB.setdefault("pions_joueurs", {})
    solde_de = _xpf_total_pions(pj.get(de, {}))
    solde_vers = _xpf_total_pions(pj.get(vers, {}))

    if not confirme:
        manque = '<div style="background:rgba(252,165,165,.12);border:1px solid #ef4444;border-radius:8px;padding:10px;margin:10px 0;color:#fca5a5">⚠️ Solde insuffisant sur le code source.</div>' if solde_de < montant else ''
        url_ok = f"/transfert-pions?cle={cle}&de={de}&vers={vers}&montant={montant}&confirme=1"
        return page(f'<h1 style="color:#a855f7;font-size:20px">🔁 Aperçu du transfert</h1>'
                    f'<div style="background:#161b22;border:1px solid #30363d;border-radius:12px;padding:16px;margin:12px 0;line-height:1.8">'
                    f'De <code style="color:#fca5a5">{de}</code> ({format(solde_de, ",")} F) <br>'
                    f'Vers <code style="color:#6ee7b7">{vers}</code> ({format(solde_vers, ",")} F)<br>'
                    f'Montant : <b style="color:#fbbf24">{format(montant, ",")} F</b></div>{manque}'
                    + ('' if solde_de < montant else
                       f'<a href="{url_ok}" style="display:inline-block;background:#059669;color:#fff;padding:12px 22px;border-radius:10px;text-decoration:none;font-weight:700">✅ Confirmer le transfert</a>')
                    + '<p style="color:#6b7280;font-size:12px;margin-top:10px">Transfert tracé (admin).</p>')

    # === EXECUTION ===
    poche_src = pj.get(de, {})
    if _xpf_total_pions(poche_src) < montant or not _debiter_pions_montant(poche_src, montant):
        return page(f'<p style="color:#fca5a5">Solde insuffisant sur {de}.</p>')
    pj[de] = poche_src
    poche_cib = pj.get(vers, {})
    _crediter_pions_montant(poche_cib, montant)
    pj[vers] = poche_cib
    DB.setdefault("transferts_pions", []).insert(0, {
        "id": secrets.token_hex(4).upper(), "de": de, "vers": vers, "montant": montant,
        "par": cle, "admin": True, "date": datetime.datetime.now().isoformat()
    })
    save_data(immediat=True)
    return page(f'<h1 style="color:#34d399;font-size:20px">✅ Transfert effectué</h1>'
                f'<p style="color:#fff"><b>{format(montant, ",")} F</b> transférés de <code style="color:#fca5a5">{de}</code> vers <code style="color:#6ee7b7">{vers}</code>.</p>'
                f'<p style="color:#94a3b8">Nouveau solde {de} : {format(_xpf_total_pions(poche_src), ",")} F · {vers} : {format(_xpf_total_pions(poche_cib), ",")} F</p>')

@app.route("/trace-vente")
def trace_vente():
    """ADMIN — Trace TOUTES les ventes d'un jeu à une date, dans toutes les listes :
    ventes de cartons, achats en pions, tickets attribués. ?cle=ADMIN[&jeu=...][&date=AAAA-MM-JJ]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    jeu_q = (request.args.get("jeu", "") or "TRIPLE").strip()
    date_q = (request.args.get("date", "") or "").strip()
    jeu_up = jeu_q.upper()

    def match(j, d):
        return jeu_up in (j or "").upper() and (not date_q or str(d or "").startswith(date_q))

    # 1) Ventes de cartons (organisatrice)
    ventes = [v for v in DB.get("ventes", []) if isinstance(v, dict) and match(v.get("jeu"), v.get("date"))]
    # 2) Achats en pions (self-service joueuse)
    pions = [c for c in DB.get("commandes_tickets_pions", []) if isinstance(c, dict) and match(c.get("jeu"), c.get("date"))]
    # 3) Tickets attribués
    tks = [t for t in DB.get("tickets", []) if isinstance(t, dict) and match(t.get("jeu"), t.get("date"))]

    tot_ventes = sum(int(v.get("total", 0) or 0) for v in ventes)
    tot_pions = sum(int(c.get("total_pions", 0) or 0) for c in pions)

    # Diagnostic : tous les jeux achetés en pions (pour repérer le nom EXACT)
    tous_jeux = {}
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict):
            j = c.get("jeu", "(sans nom)") or "(sans nom)"
            e = tous_jeux.setdefault(j, {"n": 0, "last": ""})
            e["n"] += 1
            dt = str(c.get("date", ""))[:10]
            if dt > e["last"]:
                e["last"] = dt
    diag_rows = "".join(
        f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
        f'<td style="padding:6px;color:#cbd5e1">{j}</td>'
        f'<td style="padding:6px;color:#34d399">{e["n"]}</td>'
        f'<td style="padding:6px;color:#64748b;font-size:11px">{e["last"]}</td></tr>'
        for j, e in sorted(tous_jeux.items(), key=lambda kv: -kv[1]["n"]))

    def sect(titre, rows, vide):
        return (f'<div style="font-size:13px;color:#8b949e;margin:14px 0 6px">{titre}</div>'
                + (f'<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:520px">{rows}</table></div>'
                   if rows else f'<div style="color:#6ee7b7;font-size:13px">{vide}</div>'))

    rv = "".join(
        f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
        f'<td style="padding:8px;color:#fff">{v.get("client","?")}</td>'
        f'<td style="padding:8px;color:#cbd5e1">{v.get("qty",1)}×{v.get("pack",0)} feuilles</td>'
        f'<td style="padding:8px;text-align:right;color:#fbbf24">{format(int(v.get("total",0) or 0), ",")} F</td>'
        f'<td style="padding:8px;color:#a78bfa">{v.get("mode_paiement","?")}</td>'
        f'<td style="padding:8px;color:#64748b;font-size:11px">{str(v.get("date",""))[:16].replace("T"," ")}</td></tr>'
        for v in ventes)
    rp = "".join(
        f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
        f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{c.get("code_joueur","?")}</td>'
        f'<td style="padding:8px;color:#cbd5e1">{c.get("nb_tickets","?")} ticket(s)</td>'
        f'<td style="padding:8px;text-align:right;color:#fbbf24">{format(int(c.get("total_pions",0) or 0), ",")} F pions</td>'
        f'<td style="padding:8px;color:#94a3b8">{c.get("statut","?")}</td>'
        f'<td style="padding:8px;color:#64748b;font-size:11px">{str(c.get("date",""))[:16].replace("T"," ")}</td></tr>'
        for c in pions)
    rt = "".join(
        f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
        f'<td style="padding:8px;color:#fff">{t.get("acheteur","?")}</td>'
        f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{t.get("code_acheteur","?")}</td>'
        f'<td style="padding:8px;color:#cbd5e1">série {t.get("serie","?")}</td>'
        f'<td style="padding:8px;color:#64748b;font-size:11px">{str(t.get("date",""))[:16].replace("T"," ")}</td></tr>'
        for t in tks)

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Trace vente</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:820px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7">🔎 Ventes « {jeu_q} » {("du " + date_q) if date_q else "(toutes dates)"}</h1>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin:12px 0">
        <div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Ventes cartons</div><div style="font-size:18px;font-weight:800">{len(ventes)}</div><div style="font-size:11px;color:#fbbf24">{format(tot_ventes, ",")} F</div></div>
        <div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Achats en pions</div><div style="font-size:18px;font-weight:800">{len(pions)}</div><div style="font-size:11px;color:#fbbf24">{format(tot_pions, ",")} F</div></div>
        <div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Tickets attribués</div><div style="font-size:18px;font-weight:800">{len(tks)}</div></div>
      </div>
      {sect("🎫 Ventes de cartons (espèces / virement)", rv, "Aucune vente de cartons ce jour.")}
      {sect("🪙 Achats payés en pions", rp, "Aucun achat en pions ce jour.")}
      {sect("📋 Tickets attribués", rt, "Aucun ticket attribué ce jour.")}
      <div style="font-size:13px;color:#8b949e;margin:18px 0 6px">🧭 Tous les jeux achetés en pions (pour repérer le nom exact)</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:360px"><tr style="border-bottom:2px solid #3730a3"><th style="padding:6px;text-align:left;color:#a78bfa">Jeu</th><th style="padding:6px;text-align:left;color:#a78bfa">Achats</th><th style="padding:6px;text-align:left;color:#a78bfa">Dernier</th></tr>{diag_rows or '<tr><td colspan=3 style="padding:10px;color:#94a3b8">Aucun achat en pions enregistré.</td></tr>'}</table></div>
      <div style="margin-top:14px;color:#94a3b8;font-size:12px">Filtrer une date : <code style="color:#a78bfa">&date=2026-06-26</code>. Autre jeu : <code style="color:#a78bfa">&jeu=OHANA</code>.</div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")

@app.route("/rembourser-jeu")
def rembourser_jeu():
    """ADMIN — Rembourse en pions bonus tous les achats d'un jeu (ex. TRIPLE ACTION 75)
    pour une date donnée. Aperçu d'abord, rien sans &confirme=1.
    ?cle=ADMIN[&jeu=TRIPLE ACTION 75][&date=2026-06-27][&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    jeu_q = (request.args.get("jeu", "") or "TRIPLE ACTION 75").strip()
    date_q = (request.args.get("date", "") or "").strip()
    if not date_q:
        date_q = datetime.datetime.now().date().isoformat()
    confirme = request.args.get("confirme", "") == "1"
    jeu_up = jeu_q.upper()

    cibles = []
    for c in DB.get("commandes_tickets_pions", []):
        if not isinstance(c, dict):
            continue
        if jeu_up not in (c.get("jeu", "") or "").upper():
            continue
        if date_q and not str(c.get("date", "")).startswith(date_q):
            continue
        if c.get("rembourse"):
            continue
        cibles.append(c)

    nb = len(cibles)
    total_pions = sum(int(c.get("total_pions", 0) or 0) for c in cibles)

    def page(corps):
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Remboursement</title></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:18px;color:#fff">
        <div style="max-width:680px;margin:0 auto">{corps}</div></body></html>''', mimetype="text/html; charset=utf-8")

    if not confirme:
        if not cibles:
            return page(f'<h1 style="color:#34d399;font-size:20px">Rien à rembourser</h1>'
                        f'<p style="color:#94a3b8">Aucun achat « {jeu_q} » non remboursé pour le {date_q}.</p>'
                        f'<p style="color:#6b7280;font-size:12px">Autre date ? ajoute <code style="color:#a78bfa">&date=2026-06-27</code>.</p>')
        lignes = ""
        for c in cibles:
            lignes += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
                       f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{c.get("code_joueur","?")}</td>'
                       f'<td style="padding:8px;color:#cbd5e1">{c.get("nb_tickets","?")} ticket(s)</td>'
                       f'<td style="padding:8px;text-align:right;color:#fbbf24">{format(int(c.get("total_pions",0) or 0), ",")} F</td>'
                       f'<td style="padding:8px;color:#64748b;font-size:11px">{str(c.get("date",""))[:16].replace("T"," ")}</td></tr>')
        url_ok = f"/rembourser-jeu?cle={cle}&jeu={jeu_q}&date={date_q}&confirme=1"
        return page(f'<h1 style="color:#a855f7;font-size:20px">↩️ Remboursement — {jeu_q}</h1>'
                    f'<div style="background:#161b22;border:1px solid #30363d;border-radius:12px;padding:16px;margin:12px 0;line-height:1.7">'
                    f'Date : <b>{date_q}</b><br>Achats à rembourser : <b>{nb}</b><br>'
                    f'Total à recréditer (pions bonus) : <b style="color:#fbbf24">{format(total_pions, ",")} F</b></div>'
                    f'<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:480px">'
                    f'<tr style="border-bottom:2px solid #3730a3"><th style="padding:8px;text-align:left;color:#a78bfa">Joueuse</th><th style="padding:8px;text-align:left;color:#a78bfa">Tickets</th><th style="padding:8px;text-align:right;color:#a78bfa">Montant</th><th style="padding:8px;text-align:left;color:#a78bfa">Date</th></tr>{lignes}</table></div>'
                    f'<a href="{url_ok}" style="display:inline-block;margin-top:14px;background:#059669;color:#fff;padding:12px 22px;border-radius:10px;text-decoration:none;font-weight:700">✅ Rembourser les {nb}</a>'
                    f'<p style="color:#6b7280;font-size:12px;margin-top:10px">Remboursement en pions bonus (jouables, non retirables). Apparaît dans le relevé comme « Remboursement — Jeu annulé ».</p>')

    # === EXECUTION ===
    detail = []
    faits = 0
    now = datetime.datetime.now().isoformat()
    for c in cibles:
        code = c.get("code_joueur")
        m = int(c.get("total_pions", 0) or 0)
        if not code or m <= 0:
            continue
        poche = DB.setdefault("pions_bonus_joueurs", {}).get(code, {})
        _crediter_pions_montant(poche, m)
        DB["pions_bonus_joueurs"][code] = poche
        c["rembourse"] = True
        c["rembourse_date"] = now
        detail.append({"code_joueur": code, "montant": m})
        faits += 1
    DB.setdefault("remboursements_tournoi", []).insert(0, {
        "jeu": jeu_q, "date": now, "detail": detail, "par": cle, "motif": "Remboursement vente du soir"
    })
    save_data(immediat=True)
    return page(f'<h1 style="color:#34d399;font-size:20px">✅ Remboursement effectué</h1>'
                f'<p style="color:#fff"><b>{faits}</b> achat(s) « {jeu_q} » remboursé(s) en pions bonus.</p>'
                f'<p style="color:#94a3b8">Total recrédité : <b style="color:#fbbf24">{format(sum(d["montant"] for d in detail), ",")} F</b>. Chaque joueuse voit « Remboursement — Jeu annulé » dans son relevé.</p>'
                f'<p style="color:#6b7280;font-size:12px;margin-top:8px">Relancer ce lien ne rembourse pas deux fois (les achats déjà remboursés sont ignorés).</p>')

@app.route("/bilan-qr")
def bilan_qr():
    """ADMIN — Bilan global des joueuses inscrites par le QR (publicité). ?cle=ADMIN."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    log = DB.get("rejoindre_log", [])
    deja = set(DB.get("bonus_petitsjeux_donne", []))
    acces_reg = DB.get("tickets_acheteurs", {})

    def bonus_solde(code):
        pb = DB.get("pions_bonus_joueurs", {}).get(code, {})
        return pb.get("100", 0) * 100 + pb.get("50", 0) * 50 + pb.get("20", 0) * 20 + pb.get("10", 0) * 10

    vus = set()
    inscrits = []
    par_camp = {}
    for x in log:
        code = (x.get("code", "") or "").strip().upper()
        if not code or code in vus:
            continue
        vus.add(code)
        camp = (x.get("campagne", "") or "(sans)")
        inscrits.append((code, camp))
        par_camp[camp] = par_camp.get(camp, 0) + 1

    total = len(inscrits)
    nb_acces = sum(1 for code, _ in inscrits if code in acces_reg)
    total_bonus = sum(bonus_solde(code) for code, _ in inscrits)
    doublons = [code for code, camp in inscrits if code in deja and camp == "semaine"]
    nb_double = len(doublons)
    en_trop = nb_double * 500
    nb_semaine = par_camp.get("semaine", 0)
    cadeaux_legit = nb_semaine * 500

    # Qui a joué (au moins un achat de tickets en pions, validé)
    actifs = set()
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict) and c.get("statut") == "validee":
            cj = (c.get("code_joueur", "") or "").strip().upper()
            if cj in vus:
                actifs.add(cj)
    nb_joue = len(actifs)
    nb_jamais = total - nb_joue

    def carte(label, val, coul="#fff"):
        return (f'<div style="background:#161b22;border-radius:10px;padding:14px;text-align:center">'
                f'<div style="font-size:12px;color:#8b949e;margin-bottom:4px">{label}</div>'
                f'<div style="font-size:20px;font-weight:800;color:{coul}">{val}</div></div>')

    camp_rows = ""
    for c, n in sorted(par_camp.items(), key=lambda kv: -kv[1]):
        pct = round(100 * n / total) if total else 0
        camp_rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
                      f'<td style="padding:8px;color:#a78bfa;font-weight:600">{c}</td>'
                      f'<td style="padding:8px;color:#34d399">{n} inscrite(s)</td>'
                      f'<td style="padding:8px;color:#94a3b8">{pct}%</td></tr>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Bilan QR</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:760px;margin:0 auto">
      <h1 style="font-size:21px;color:#a855f7;margin-bottom:4px">📊 Bilan des inscrites par QR</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:14px">Vue d'ensemble de toutes les joueuses venues par la publicité.</div>

      <div style="font-size:13px;color:#8b949e;margin:6px 0">Participation</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px">
        {carte("Inscrites au total", total, "#fff")}
        {carte("Peuvent se connecter", f"{nb_acces} / {total}", "#34d399")}
        {carte("Ont déjà joué", nb_joue, "#34d399")}
        {carte("N'ont jamais joué", nb_jamais, "#fbbf24")}
      </div>

      <div style="font-size:13px;color:#8b949e;margin:6px 0">Pions bonus</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px">
        {carte("Bonus en circulation", format(total_bonus, ",") + " F", "#fbbf24")}
        {carte("Cadeaux d'inscription", format(cadeaux_legit, ",") + " F", "#94a3b8")}
        {carte("Doublons « semaine »", nb_double, "#fca5a5")}
        {carte("Bonus en trop (doublons)", format(en_trop, ",") + " F", "#fca5a5")}
      </div>

      <div style="font-size:13px;color:#8b949e;margin:6px 0">Par campagne</div>
      <table style="width:100%;border-collapse:collapse;font-size:14px;margin-bottom:14px">{camp_rows or '<tr><td style="padding:10px;color:#6ee7b7">Aucune inscription.</td></tr>'}</table>

      <div style="background:#161b22;border:1px solid #30363d;border-radius:10px;padding:14px;font-size:13px;color:#cbd5e1;line-height:1.7">
        💡 Les bonus sont <b>non retirables</b> : aucun impact cash, même les doublons.<br>
        🔧 Détail joueuse par joueuse : <code style="color:#a78bfa">/qr-inscrits?cle={cle}</code><br>
        🧹 Nettoyer les {nb_double} doublon(s) : <code style="color:#a78bfa">/corriger-double-bonus?cle={cle}</code>
      </div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")

@app.route("/qr-inscrits")
def qr_inscrits():
    """ADMIN — Liste COMPLÈTE des joueuses inscrites par le QR (publicité) :
    code, campagne, date, solde bonus, doublon éventuel, accès. ?cle=ADMIN[&campagne=X]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    filtre = (request.args.get("campagne", "") or "").strip()
    log = DB.get("rejoindre_log", [])
    deja = set(DB.get("bonus_petitsjeux_donne", []))
    acces = DB.get("tickets_acheteurs", {})

    def bonus_solde(code):
        pb = DB.get("pions_bonus_joueurs", {}).get(code, {})
        return pb.get("100", 0) * 100 + pb.get("50", 0) * 50 + pb.get("20", 0) * 20 + pb.get("10", 0) * 10

    # déduplique par code (garde la 1re occurrence = inscription)
    vus = set()
    inscrits = []
    for x in log:
        code = (x.get("code", "") or "").strip().upper()
        if not code or code in vus:
            continue
        vus.add(code)
        camp = (x.get("campagne", "") or "(sans)")
        if filtre and camp != filtre:
            continue
        inscrits.append({
            "code": code, "nom": x.get("nom", "?"), "camp": camp,
            "date": (x.get("date", "") or "")[:16].replace("T", " "),
            "bonus": bonus_solde(code),
            "double": (code in deja and camp == "semaine"),
            "acces": code in acces,
        })
    inscrits.sort(key=lambda r: r["date"], reverse=True)

    total = len(inscrits)
    nb_double = sum(1 for r in inscrits if r["double"])
    total_bonus = sum(r["bonus"] for r in inscrits)

    rows = ""
    for r in inscrits:
        dbl = '<span style="color:#fca5a5;font-weight:700">⚠️ doublon</span>' if r["double"] else '<span style="color:#6ee7b7">ok</span>'
        acc = '✅' if r["acces"] else '❌'
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
                 f'<td style="padding:8px;color:#fff">{r["nom"]}</td>'
                 f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{r["code"]}</td>'
                 f'<td style="padding:8px;color:#94a3b8">{r["camp"]}</td>'
                 f'<td style="padding:8px;text-align:right;color:#fbbf24">{format(r["bonus"], ",")}</td>'
                 f'<td style="padding:8px;text-align:center">{acc}</td>'
                 f'<td style="padding:8px;text-align:center">{dbl}</td>'
                 f'<td style="padding:8px;color:#64748b;font-size:11px">{r["date"]}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="7" style="padding:18px;text-align:center;color:#94a3b8">Aucune inscription QR.</td></tr>'

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Inscrites QR</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:900px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7">📲 Codes générés par le QR{(" · " + filtre) if filtre else ""}</h1>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin:12px 0">
        <div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Inscrites</div><div style="font-size:18px;font-weight:800">{total}</div></div>
        <div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Doublons « semaine »</div><div style="font-size:18px;font-weight:800;color:#fca5a5">{nb_double}</div></div>
        <div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Bonus en circulation</div><div style="font-size:18px;font-weight:800;color:#fbbf24">{format(total_bonus, ",")}</div></div>
      </div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:620px">
      <tr style="border-bottom:2px solid #3730a3"><th style="padding:8px;text-align:left;color:#a78bfa">Nom</th><th style="padding:8px;text-align:left;color:#a78bfa">Code</th><th style="padding:8px;text-align:left;color:#a78bfa">Campagne</th><th style="padding:8px;text-align:right;color:#a78bfa">Bonus</th><th style="padding:8px;text-align:center;color:#a78bfa">Accès</th><th style="padding:8px;text-align:center;color:#a78bfa">État</th><th style="padding:8px;text-align:left;color:#a78bfa">Inscrite le</th></tr>
      {rows}</table></div>
      <div style="margin-top:12px;color:#94a3b8;font-size:12px">⚠️ doublon = a reçu 500 F à l'inscription ET par l'outil. Utilise <code style="color:#a78bfa">/corriger-double-bonus</code> pour nettoyer.</div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")

@app.route("/diag-campagnes")
def diag_campagnes():
    """Combien d'inscrits par affiche (mini vs premier). ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    log = DB.get("rejoindre_log", [])
    par = {}
    for x in log:
        c = (x.get("campagne") or "(inconnu)")
        par[c] = par.get(c, 0) + 1
    total = len(log)
    lignes = ""
    for c, n in sorted(par.items(), key=lambda x: -x[1]):
        pct = round(100 * n / total) if total else 0
        lignes += f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)"><td style="padding:10px;font-weight:600;color:#a78bfa">{c}</td><td style="padding:10px;color:#34d399">{n} inscrit(s)</td><td style="padding:10px;color:#94a3b8">{pct}%</td></tr>'
    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Campagnes</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:600px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7">📊 D'où viennent tes joueurs</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:14px">Total inscrits par la pub : <b style="color:#fff">{total}</b></div>
      <table style="width:100%;border-collapse:collapse">{lignes or '<tr><td style="padding:10px;color:#6ee7b7">Aucune inscription pour le moment.</td></tr>'}</table>
      <div style="margin-top:14px;color:#94a3b8;font-size:12px">« mini » = affiche P6 50 000 · « premier » = affiche OHANA 500 000. Mets ton budget pub sur la meilleure.</div>
    </div></body></html>'''

@app.route("/journal-operations")
def journal_operations():
    """ADMIN — Journal central de TOUTES les opérations entre organisatrices et
    joueuses. ?cle=ADMIN[&org=CODE][&joueur=CODE][&date=AAAA-MM-JJ][&limit=N]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    f_org = (request.args.get("org", "") or "").strip().upper()
    f_joueur = (request.args.get("joueur", "") or "").strip().upper()
    f_date = (request.args.get("date", "") or "").strip()
    try:
        limit = int(request.args.get("limit", 250) or 250)
    except Exception:
        limit = 250
    codes = DB.get("codes", {})

    def i(x):
        try:
            return int(float(x or 0))
        except Exception:
            return 0

    ops = []
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict):
            ops.append({"date": c.get("date", ""), "type": "Achat pions", "coul": "#fbbf24",
                        "org": c.get("code_org", ""), "joueur": c.get("code_joueur", ""),
                        "montant": i(c.get("montant_paye")), "statut": c.get("statut", ""),
                        "info": f'{c.get("nb_pions","?")} pions'})
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict):
            ops.append({"date": t.get("date", ""), "type": "Crédit pions (org→joueuse)", "coul": "#34d399",
                        "org": t.get("code_org", ""), "joueur": t.get("code_joueur", ""),
                        "montant": i(t.get("montant_total")), "statut": "", "info": t.get("mode_paiement", "")})
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict):
            ops.append({"date": c.get("date", ""), "type": "Achat tickets", "coul": "#818cf8",
                        "org": c.get("code_org", ""), "joueur": c.get("code_joueur", ""),
                        "montant": i(c.get("total_pions")), "statut": c.get("statut", ""), "info": c.get("jeu", "")})
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict):
            ops.append({"date": g.get("date", ""), "type": "Gain", "coul": "#f472b6",
                        "org": g.get("code_org", ""), "joueur": g.get("code_gagnant", ""),
                        "montant": i(g.get("montant_credite") or g.get("montant_gain")), "statut": "", "info": g.get("jeu", "")})
    for r in DB.get("demandes_retrait", []):
        if isinstance(r, dict):
            ops.append({"date": r.get("date", ""), "type": "Retrait", "coul": "#fb923c",
                        "org": r.get("code_org", ""), "joueur": r.get("code_joueur", ""),
                        "montant": i(r.get("montant_demande")), "statut": r.get("statut", ""), "info": ""})
    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict):
            for det in (rb.get("detail") or []):
                if isinstance(det, dict):
                    ops.append({"date": rb.get("date", ""), "type": "Remboursement", "coul": "#fca5a5",
                                "org": rb.get("code_org", ""), "joueur": det.get("code_joueur", ""),
                                "montant": i(det.get("montant")), "statut": "", "info": rb.get("jeu", "")})
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            ops.append({"date": t.get("date", ""), "type": "Transfert", "coul": "#c4b5fd",
                        "org": t.get("par", ""), "joueur": str(t.get("de", "")) + "→" + str(t.get("vers", "")),
                        "montant": i(t.get("montant")), "statut": "admin" if t.get("admin") else "", "info": ""})
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict):
            for cj in (c.get("codes") or []):
                ops.append({"date": c.get("date", ""), "type": "Crédit groupe", "coul": "#5eead4",
                            "org": c.get("par", "ADMIN"), "joueur": cj,
                            "montant": i(c.get("nb_pions")) * i(c.get("valeur_pion")), "statut": "", "info": c.get("motif", "")})
    # --- Crédits / retraits de pions (joueuse) ---
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict):
            ops.append({"date": c.get("date", ""), "type": "Crédit pions (admin→joueuse)", "coul": "#34d399",
                        "org": c.get("par", "ADMIN"), "joueur": c.get("code_joueur", ""),
                        "montant": i(c.get("valeur_pion")) * i(c.get("nb_pions")), "statut": "", "info": "crédit admin"})
    for c in DB.get("corrections_pions", []):
        if isinstance(c, dict):
            ops.append({"date": c.get("date", ""), "type": "Retrait pions (joueuse)", "coul": "#fca5a5",
                        "org": c.get("par", "ADMIN"), "joueur": c.get("code_joueur", ""),
                        "montant": i(c.get("montant_retire")), "statut": "", "info": c.get("motif", "")})
    # --- Crédits / retraits de la poche ORGANISATRICE ---
    for c in DB.get("credits_poche_org", []):
        if isinstance(c, dict):
            ops.append({"date": c.get("date", ""), "type": "Crédit poche ORG", "coul": "#22d3ee",
                        "org": c.get("code_org", ""), "joueur": "— (organisatrice)",
                        "montant": i(c.get("montant")), "statut": "", "info": c.get("motif", "")})
    for r in DB.get("remboursements_org", []):
        if isinstance(r, dict):
            ops.append({"date": r.get("date", ""), "type": "Retrait poche ORG", "coul": "#f59e0b",
                        "org": r.get("org", ""), "joueur": "— (organisatrice)",
                        "montant": i(r.get("montant")), "statut": "", "info": "clôture / remboursement org"})

    # Filtres
    def garde(o):
        if f_org and (o.get("org", "") or "").upper() != f_org:
            return False
        if f_joueur and f_joueur not in (o.get("joueur", "") or "").upper():
            return False
        if f_date and not str(o.get("date", "")).startswith(f_date):
            return False
        return True

    ops = [o for o in ops if garde(o)]
    total = len(ops)
    ops.sort(key=lambda o: str(o.get("date", "")), reverse=True)
    ops = ops[:limit]

    onom = lambda o: (codes.get(o, {}).get("nom", o) if o else "—")
    rows = ""
    for o in ops:
        st = o.get("statut", "")
        stbadge = f'<span style="font-size:10px;color:#94a3b8"> · {st}</span>' if st else ''
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:7px;color:#64748b;font-size:11px;white-space:nowrap">{str(o.get("date",""))[:16].replace("T"," ")}</td>'
                 f'<td style="padding:7px"><span style="color:{o.get("coul","#fff")};font-weight:600;font-size:12px">{o.get("type","")}</span>{stbadge}</td>'
                 f'<td style="padding:7px;font-size:12px;color:#fbbf24">{onom(o.get("org",""))}</td>'
                 f'<td style="padding:7px;font-family:monospace;font-size:12px;color:#a78bfa">{o.get("joueur","")}</td>'
                 f'<td style="padding:7px;text-align:right;font-weight:700;color:#fff;white-space:nowrap">{format(o.get("montant",0), ",")} F</td>'
                 f'<td style="padding:7px;color:#94a3b8;font-size:11px">{o.get("info","")}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="6" style="padding:20px;text-align:center;color:#94a3b8">Aucune opération pour ces filtres.</td></tr>'

    filtres_actifs = " · ".join(filter(None, [
        ("org=" + f_org) if f_org else "",
        ("joueuse=" + f_joueur) if f_joueur else "",
        ("date=" + f_date) if f_date else ""])) or "tout"

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Journal des opérations</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:960px;margin:0 auto">
      <h1 style="font-size:21px;color:#a855f7;margin-bottom:2px">📒 Journal des opérations</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:12px">Toutes les opérations entre organisatrices et joueuses · filtre : <b style="color:#fff">{filtres_actifs}</b> · {min(total, limit)} affichées sur {total}</div>
      <div style="background:#161b22;border:1px solid #30363d;border-radius:10px;padding:10px 12px;margin-bottom:12px;color:#94a3b8;font-size:12px;line-height:1.6">
        🔎 Filtrer : ajoute <code style="color:#a78bfa">&org=CODE</code>, <code style="color:#a78bfa">&joueur=CODE</code>, <code style="color:#a78bfa">&date=2026-06-27</code> ou <code style="color:#a78bfa">&limit=500</code> à l'adresse.
      </div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:680px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:7px;color:#a78bfa">Date</th><th style="padding:7px;color:#a78bfa">Opération</th><th style="padding:7px;color:#a78bfa">Organisatrice</th><th style="padding:7px;color:#a78bfa">Joueuse</th><th style="padding:7px;color:#a78bfa;text-align:right">Montant</th><th style="padding:7px;color:#a78bfa">Détail</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")

@app.route("/rapport-org")
def rapport_org():
    """ADMIN — Rapport de solde d'un organisateur + actions (rembourser sa poche,
    fermer son code). ?cle=ADMIN&org=CODE[&action=vider|fermer&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    org = (request.args.get("org", "") or "").strip().upper()
    action = (request.args.get("action", "") or "").strip()
    confirme = request.args.get("confirme", "") == "1"

    def page(corps):
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Rapport organisateur</title></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:18px;color:#fff">
        <div style="max-width:680px;margin:0 auto">{corps}</div></body></html>''', mimetype="text/html; charset=utf-8")

    if not org:
        return page('<h1 style="color:#a855f7;font-size:20px">🧾 Rapport organisateur</h1>'
                    '<p style="color:#94a3b8">Ajoute <code style="color:#fde68a">&org=CODE</code> (ex. <code style="color:#fde68a">&org=CPFRD66H</code> pour HEINI).</p>')

    oinfo = DB.get("codes", {}).get(org)
    if not oinfo:
        return page(f'<p style="color:#fca5a5">Organisateur {org} introuvable.</p>')

    nom = oinfo.get("nom", "") or "(sans nom)"
    poche = DB.get("pions_org", {}).get(org, {})
    solde = _xpf_total_pions(poche)

    # === ACTIONS ===
    if action == "vider" and confirme:
        DB.setdefault("remboursements_org", []).insert(0, {
            "org": org, "nom": nom, "montant": solde, "par": cle,
            "date": datetime.datetime.now().isoformat()})
        DB.setdefault("pions_org", {})[org] = {}
        save_data(immediat=True)
        return page(f'<h1 style="color:#34d399;font-size:20px">✅ Poche remboursée</h1>'
                    f'<p style="color:#fff"><b>{format(solde, ",")} F</b> de pions retirés de la poche de <b>{nom}</b> (remboursement enregistré).</p>'
                    f'<p style="margin-top:10px"><a href="/rapport-org?cle={cle}&org={org}" style="color:#a78bfa">← Revoir le rapport</a></p>')
    if action == "fermer" and confirme:
        oinfo["actif"] = False
        DB["codes"][org] = oinfo
        save_data(immediat=True)
        return page(f'<h1 style="color:#34d399;font-size:20px">🔒 Code fermé</h1>'
                    f'<p style="color:#fff">Le code organisateur <b>{nom}</b> ({org}) est désormais <b>désactivé</b>.</p>'
                    f'<p style="margin-top:10px"><a href="/rapport-org?cle={cle}&org={org}" style="color:#a78bfa">← Revoir le rapport</a></p>')

    # === RAPPORT ===
    ventes_org = [v for v in DB.get("ventes", []) if (v.get("code_org") or "").upper() == org]
    total_vendu = sum(int(v.get("total", 0) or 0) for v in ventes_org)
    # transactions joueuse <-> org
    tjo = [t for t in DB.get("transactions_joueur_org", []) if (t.get("code_org") or "").upper() == org]
    recu_joueuses = sum(int(t.get("montant", 0) or 0) for t in tjo if int(t.get("montant", 0) or 0) > 0)

    deco = " · ".join(f'{n}×{v}' for v, n in sorted(poche.items(), key=lambda kv: -int(kv[0])) if n) or "vide"
    badge_actif = ('<span style="color:#6ee7b7">✅ actif</span>' if oinfo.get("actif") else '<span style="color:#fca5a5">🔒 fermé</span>')

    url_vider = f"/rapport-org?cle={cle}&org={org}&action=vider&confirme=1"
    url_fermer = f"/rapport-org?cle={cle}&org={org}&action=fermer&confirme=1"

    return page(f'''
      <h1 style="font-size:21px;color:#fbbf24">🧾 {nom} <span style="font-size:13px;color:#94a3b8">({org})</span></h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:14px">Statut : {badge_actif}</div>

      <div style="background:#161b22;border:1px solid #30363d;border-radius:12px;padding:16px;margin-bottom:14px">
        <div style="font-size:13px;color:#8b949e">💰 Solde de sa poche de pions (à lui rembourser)</div>
        <div style="font-size:30px;font-weight:800;color:#34d399;margin:4px 0">{format(solde, ",")} F</div>
        <div style="font-size:12px;color:#94a3b8">Détail : {deco}</div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px">
        <div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Ventes enregistrées</div><div style="font-size:18px;font-weight:800">{len(ventes_org)}</div><div style="font-size:11px;color:#fbbf24">{format(total_vendu, ",")} F</div></div>
        <div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Reçu des joueuses</div><div style="font-size:18px;font-weight:800;color:#fbbf24">{format(recu_joueuses, ",")} F</div></div>
      </div>

      <div style="background:#1a1830;border-radius:12px;padding:16px">
        <div style="font-size:14px;color:#fff;margin-bottom:10px;font-weight:600">Clôture du compte</div>
        <a href="{url_vider}" style="display:block;background:#059669;color:#fff;padding:11px;border-radius:9px;text-decoration:none;font-weight:700;text-align:center;margin-bottom:8px">💸 Rembourser & vider sa poche ({format(solde, ",")} F)</a>
        <a href="{url_fermer}" style="display:block;background:#b91c1c;color:#fff;padding:11px;border-radius:9px;text-decoration:none;font-weight:700;text-align:center">🔒 Fermer son code organisateur</a>
        <div style="color:#6b7280;font-size:11px;margin-top:8px">Fais d'abord le remboursement, puis ferme le code. Le détail de ses ventes : <code style="color:#a78bfa">/diag-achats?cle={cle}&org={org}</code></div>
      </div>''')

@app.route("/diag-achats")
def diag_achats():
    """RAPPORT — Achats de tickets/PDF par organisateur (pour remboursement).
    ?cle=CODE_ADMIN. Optionnel &org=CODE pour filtrer un seul organisateur."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN a l'adresse.", status=403, mimetype="text/plain; charset=utf-8")
    org_filtre = (request.args.get("org", "") or "").strip().upper()
    codes_info = DB.get("codes", {})
    fv = DB.get("feuilles_vendues", {})

    par_org = {}
    for v in DB.get("ventes", []):
        co = (v.get("code_org") or "").upper()
        if not co or co == "ADMIN":
            continue
        if org_filtre and co != org_filtre:
            continue
        par_org.setdefault(co, []).append(v)

    def total_org(vs):
        return sum(int(x.get("total", 0) or 0) for x in vs)

    grand_total = 0
    blocs = ""
    for co in sorted(par_org.keys(), key=lambda c: -total_org(par_org[c])):
        vs = par_org[co]
        nom = codes_info.get(co, {}).get("nom", "") or "(sans nom)"
        tot = total_org(vs)
        grand_total += tot
        tot_feuilles = sum(int(x.get("total_feuilles", 0) or 0) for x in vs)
        vendues = sum(len(p) for p in fv.get(co, {}).values())
        lignes = ""
        for v in sorted(vs, key=lambda x: x.get("date", ""), reverse=True):
            dte = (v.get("date", "") or "")[:10]
            lignes += ('<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                       f'<td style="padding:7px;color:#94a3b8;white-space:nowrap">{dte}</td>'
                       f'<td style="padding:7px">{v.get("jeu","")}</td>'
                       f'<td style="padding:7px;color:#94a3b8">{v.get("serie","")}</td>'
                       f'<td style="padding:7px;text-align:right">{int(v.get("total_feuilles",0) or 0)}</td>'
                       f'<td style="padding:7px;text-align:right;color:#34d399;font-weight:600">{int(v.get("total",0) or 0):,} F</td>'
                       f'<td style="padding:7px;color:#c4b5fd">{(v.get("client","") or "")[:18]}</td></tr>')
        blocs += ('<div style="background:#1a1830;border-radius:12px;padding:14px;margin-bottom:14px">'
                  f'<div style="font-size:17px;font-weight:700;color:#fbbf24">{nom} <span style="font-size:12px;color:#94a3b8;font-weight:400">({co})</span></div>'
                  f'<div style="font-size:15px;color:#fff;margin:6px 0 4px">💰 Total : <b style="color:#34d399">{tot:,} F</b></div>'
                  f'<div style="font-size:12px;color:#94a3b8;margin-bottom:8px">{len(vs)} ligne(s) · {tot_feuilles:,} feuilles · {vendues:,} feuilles vendues aux joueurs</div>'
                  '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">'
                  '<tr style="color:#a78bfa;text-align:left"><th style="padding:7px">Date</th><th style="padding:7px">Jeu</th><th style="padding:7px">Série</th><th style="padding:7px;text-align:right">Feuilles</th><th style="padding:7px;text-align:right">Montant</th><th style="padding:7px">Client</th></tr>'
                  f'{lignes}</table></div></div>')

    if not blocs:
        blocs = ('<div style="color:#94a3b8;padding:20px;text-align:center">Aucun achat trouvé'
                 + (f' pour {org_filtre}' if org_filtre else '') + '.</div>')

    titre_filtre = ''
    if org_filtre:
        titre_filtre = ' — ' + (codes_info.get(org_filtre, {}).get("nom", "") or org_filtre)

    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Rapport d'achats</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:780px;margin:0 auto">
      <h1 style="font-size:20px;color:#34d399">🧾 Rapport d'achats de tickets{titre_filtre}</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:16px">Ce que chaque organisateur a reçu de l'administrateur, pour le remboursement.</div>
      {blocs}
      <div style="background:#0d2818;border:1px solid #10b981;border-radius:12px;padding:14px;margin-top:4px;font-size:16px">TOTAL GÉNÉRAL : <b style="color:#34d399">{grand_total:,} F</b></div>
      <div style="margin-top:14px;color:#9ca3af;font-size:12px;line-height:1.5">📌 La colonne <b>Client</b> t'aide à distinguer : les lignes sans client (ou avec le nom de l'organisateur) = ce qu'il t'a acheté ; les lignes avec un nom de joueur = ce qu'il a revendu.<br>Astuce : ajoute <b>&org=CODE</b> à l'adresse pour un seul organisateur (ex : <b>&org=CPFRD66H</b> pour HEINI).</div>
    </div></body></html>'''

def _reset_pdfs_vendus():
    """Efface les PDF vendus : fichiers + compteurs (feuilles_vendues) + historique
    des ventes (ventes + acces_docs). GARDE les comptes joueurs (codes + pions) et
    les organisateurs. Nettoie juste les liens PDF morts sur les tickets joueurs."""
    global DB
    # 1) Collecter et supprimer les fichiers PDF references (ventes + tickets)
    paths = set()
    for v in DB.get("ventes", []):
        u = v.get("pdf_url") or ""
        if u:
            paths.add("/data/pdfs/" + u.split("/")[-1].replace(".pdf", "") + ".pdf")
    for t in DB.get("tickets", []):
        u = t.get("pdf_url") or ""
        if u:
            paths.add("/data/pdfs/" + u.split("/")[-1].replace(".pdf", "") + ".pdf")
    n_fichiers = 0
    for p in paths:
        try:
            if os.path.exists(p):
                os.remove(p)
                n_fichiers += 1
        except Exception:
            pass
    n_ventes = len(DB.get("ventes", []))
    # 2) Effacer historique des ventes + compteurs de feuilles
    DB["ventes"] = []
    DB["feuilles_vendues"] = {}
    DB["acces_docs"] = {}
    # 3) Nettoyer les liens PDF morts sur les tickets joueurs (on garde code + pions + nom)
    n_tickets = 0
    for t in DB.get("tickets", []):
        if t.get("pdf_url") or t.get("page_debut") or t.get("page_fin"):
            t["pdf_url"] = None
            t["page_debut"] = None
            t["page_fin"] = None
            n_tickets += 1
    # 4) Journaliser
    DB.setdefault("historique_resets", []).insert(0, {
        "date": datetime.datetime.now().isoformat(),
        "fichiers_supprimes": n_fichiers,
        "ventes_effacees": n_ventes,
        "tickets_nettoyes": n_tickets
    })
    save_data(immediat=True)
    return {"fichiers": n_fichiers, "ventes": n_ventes, "tickets_nettoyes": n_tickets}

@app.route("/reset-tournois", methods=["GET", "POST"])
def reset_tournois():
    """ADMIN — Remise a zero des PDF vendus (fichiers + compteurs + historique ventes).
    GET ?cle=ADMIN : page de confirmation. POST {cle, confirm:'OUI'} : execute. IRREVERSIBLE.
    Garde les comptes joueurs (codes + pions) et les organisateurs."""
    global DB
    DB = load_data()
    if request.method == "POST":
        d = request.json or {}
        cle_p = (d.get("cle", "") or "").strip().upper()
        info_p = DB.get("codes", {}).get(cle_p)
        if not (info_p and info_p.get("admin")):
            return jsonify({"ok": False, "msg": "Accès refusé"}), 403
        if (d.get("confirm", "") or "").strip().upper() != "OUI":
            return jsonify({"ok": False, "msg": "Confirmation manquante"}), 400
        res = _reset_pdfs_vendus()
        return jsonify({"ok": True, **res})

    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN a l'adresse.", status=403, mimetype="text/plain; charset=utf-8")
    n_ventes = len(DB.get("ventes", []))
    fv = DB.get("feuilles_vendues", {})
    n_feuilles = sum(len(p) for org in fv.values() for p in org.values())
    paths = set()
    for v in DB.get("ventes", []):
        u = v.get("pdf_url") or ""
        if u:
            paths.add(u.split("/")[-1])
    for t in DB.get("tickets", []):
        u = t.get("pdf_url") or ""
        if u:
            paths.add(u.split("/")[-1])
    n_pdf = len(paths)

    PAGE = '''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Repartir a zero</title></head>
<body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
<div style="max-width:560px;margin:0 auto">
  <h1 style="font-size:20px;color:#f87171">⚠️ Repartir sur de nouvelles bases</h1>
  <div style="background:#2a1015;border:1px solid #ef4444;border-radius:12px;padding:16px;margin:14px 0">
    <div style="font-size:14px;color:#fecaca;margin-bottom:10px">Tu es sur le point d'effacer <b>DÉFINITIVEMENT</b> :</div>
    <div style="font-size:15px;line-height:1.9">
      🗂️ <b>@@NPDF@@</b> fichier(s) PDF vendus<br>
      📊 <b>@@NFEUILLES@@</b> feuille(s) dans les compteurs<br>
      🧾 <b>@@NVENTES@@</b> ligne(s) d'historique de ventes
    </div>
  </div>
  <div style="background:#0d2818;border:1px solid #10b981;border-radius:12px;padding:12px;font-size:13px;color:#a7f3d0;margin-bottom:16px">
    ✅ Tes <b>joueurs gardent leur code et leurs pions</b>, et tes organisateurs restent. On efface seulement les PDF et leur historique.
  </div>
  <button id="btn" onclick="effacer()" style="width:100%;padding:16px;background:#ef4444;color:#fff;border:none;border-radius:12px;font-size:16px;font-weight:800;cursor:pointer">EFFACER DÉFINITIVEMENT ET REPARTIR À ZÉRO</button>
  <div id="res" style="margin-top:16px;font-size:15px;text-align:center"></div>
  <div style="margin-top:18px;color:#6b7280;font-size:12px;text-align:center">Pense à avoir fait tes remboursements avant (page /diag-achats).</div>
</div>
<script>
async function effacer(){
  if(!confirm("Es-tu vraiment sûre ? Cette action est IRRÉVERSIBLE.")) return;
  var btn=document.getElementById('btn'); btn.disabled=true; btn.style.opacity=.6; btn.textContent='Effacement en cours...';
  try{
    var r=await fetch('/reset-tournois',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({cle:'@@CLE@@',confirm:'OUI'})});
    var d=await r.json();
    if(d.ok){
      document.getElementById('res').innerHTML='<div style="background:#0d2818;border:1px solid #10b981;border-radius:10px;padding:14px;color:#34d399">✅ Terminé ! '+d.fichiers+' PDF supprimés · '+d.ventes+' ventes effacées · '+d.tickets_nettoyes+' tickets nettoyés.<br>Tu peux repartir sur de nouvelles bases. 🌿</div>';
      btn.style.display='none';
    } else { document.getElementById('res').innerHTML='<span style="color:#f87171">❌ '+(d.msg||'Erreur')+'</span>'; btn.disabled=false; btn.style.opacity=1; btn.textContent='EFFACER DÉFINITIVEMENT ET REPARTIR À ZÉRO'; }
  }catch(e){ document.getElementById('res').innerHTML='<span style="color:#f87171">❌ Erreur de connexion</span>'; btn.disabled=false; btn.style.opacity=1; }
}
</script></body></html>'''
    PAGE = PAGE.replace("@@NPDF@@", str(n_pdf)).replace("@@NFEUILLES@@", str(n_feuilles)).replace("@@NVENTES@@", str(n_ventes)).replace("@@CLE@@", cle)
    return PAGE

@app.route("/diag-pions")
def diag_pions():
    """Diagnostic LECTURE SEULE des pions d'un joueur : solde dépensable réel,
    ancienne réserve (non dépensable), commandes en attente. ?cle=CODE_ADMIN requis,
    &code=CODE_JOUEUR pour un joueur précis."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info_cle = DB.get("codes", {}).get(cle)
    if not (info_cle and info_cle.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN a l'adresse.",
                        status=403, mimetype="text/plain; charset=utf-8")

    code = (request.args.get("code", "") or "").strip().upper()
    pj_all = DB.get("pions_joueurs", {})
    vieux = DB.get("pions", {})
    cmds = DB.get("commandes_pions_joueurs", [])

    def total_xpf(dico):
        t = 0
        for v, n in dico.items():
            try:
                t += int(v) * int(n)
            except Exception:
                pass
        return t

    if code:
        pj = pj_all.get(code, {})
        tot = total_xpf(pj)
        vieux_n = vieux.get(code, 0)
        pend = [c for c in cmds if (c.get("code_joueur", "") or "").upper() == code and c.get("statut") == "en_attente_validation"]
        pend_xpf = 0
        for c in pend:
            try:
                pend_xpf += int(c.get("nb_pions", 0)) * int(c.get("valeur_pion", 0))
            except Exception:
                pass
        bloc_vieux = (f'<div style="background:#7f1d1d;color:#fecaca;padding:12px;border-radius:8px;margin-top:12px;font-weight:600">⚠️ {vieux_n} pion(s) dans l\'ANCIENNE réserve (non dépensables au jeu). À remettre avec « 🛠️ Recréditer un joueur ».</div>' if vieux_n else '')
        bloc_pend = (f'<div style="background:#854d0e;color:#fde68a;padding:12px;border-radius:8px;margin-top:12px;font-weight:600">⏳ {len(pend)} commande(s) de pions EN ATTENTE de validation = {pend_xpf} XPF. Le joueur a payé mais ce n\'est PAS encore dépensable tant qu\'un admin ne valide pas.</div>' if pend else '')
        corps = f'''
          <h2 style="color:#a78bfa;font-size:18px;margin:0 0 12px">Joueur {code}</h2>
          <div style="background:#065f46;color:#6ee7b7;padding:16px;border-radius:10px;font-size:24px;font-weight:800;text-align:center">Solde DÉPENSABLE : {tot} XPF</div>
          <div style="font-size:14px;color:#fff;margin:12px 0;line-height:1.9">
            Pions de 100 : <b>{pj.get("100", 0)}</b><br>
            Pions de 50 : <b>{pj.get("50", 0)}</b><br>
            Pions de 20 : <b>{pj.get("20", 0)}</b><br>
            Pions de 10 : <b>{pj.get("10", 0)}</b>
          </div>
          {bloc_vieux}
          {bloc_pend}
          <div style="margin-top:14px;color:#94a3b8;font-size:13px">Si le « solde dépensable » est plus bas que le prix du ticket, c\'est pour ça que l\'achat est refusé.</div>
        '''
    else:
        anomalies = ""
        for c, n in vieux.items():
            if n:
                anomalies += f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)"><td style="padding:8px;font-family:monospace;color:#a78bfa">{c}</td><td style="padding:8px;color:#fca5a5">{n} pion(s) dans l\'ancienne réserve (non dépensables)</td></tr>'
        pend_par = {}
        for c in cmds:
            if c.get("statut") == "en_attente_validation":
                k = (c.get("code_joueur", "") or "").upper()
                try:
                    pend_par[k] = pend_par.get(k, 0) + int(c.get("nb_pions", 0)) * int(c.get("valeur_pion", 0))
                except Exception:
                    pass
        for k, v in sorted(pend_par.items(), key=lambda x: -x[1]):
            anomalies += f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)"><td style="padding:8px;font-family:monospace;color:#a78bfa">{k}</td><td style="padding:8px;color:#fde68a">{v} XPF en attente de validation (payé mais pas dépensable)</td></tr>'
        corps = f'''<h2 style="color:#a78bfa;font-size:18px;margin:0 0 12px">Anomalies de pions (tous les joueurs)</h2>
          <table style="width:100%;border-collapse:collapse">{anomalies or '<tr><td style="padding:12px;color:#6ee7b7">Aucune anomalie : aucun pion coincé, aucune commande en attente.</td></tr>'}</table>
          <div style="margin-top:14px;color:#94a3b8;font-size:13px">Pour un joueur précis, ajoute <code style="color:#a78bfa">&amp;code=CODEJOUEUR</code> à l\'adresse.</div>'''

    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1"><title>Diagnostic pions</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:720px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin:4px 0 16px">🪙 Diagnostic des pions joueur</h1>
      {corps}
    </div></body></html>'''

@app.route("/diagnostic-pdf")
def diagnostic_pdf():
    """Diagnostic des PDF : présents / manquants, groupés par organisateur."""
    global DB
    DB = load_data()
    org_filtre = request.args.get("org", "").strip().upper()
    tickets = DB.get("tickets", [])

    orgs = {}
    total_tickets = 0
    total_present = 0
    total_manquant = 0
    total_sans = 0

    for t in tickets:
        co = t.get("code_org", "?") or "?"
        if org_filtre and co != org_filtre:
            continue
        if co not in orgs:
            nom_org = DB.get("codes", {}).get(co, {}).get("nom", co)
            orgs[co] = {"nom": nom_org, "tickets": [], "present": 0, "manquant": 0, "sans": 0}
        pdf_url = t.get("pdf_url")
        statut = "sans"
        if pdf_url:
            pdf_id = pdf_url.split("/")[-1].replace(".pdf", "")
            pdf_path = f"/data/pdfs/{pdf_id}.pdf"
            statut = "present" if os.path.exists(pdf_path) else "manquant"
        orgs[co]["tickets"].append({
            "acheteur": t.get("acheteur", "?"),
            "jeu": t.get("jeu", "?"),
            "serie": t.get("serie", "?"),
            "code_acheteur": t.get("code_acheteur", ""),
            "statut": statut,
            "date": t.get("date", "")
        })
        orgs[co][statut] += 1
        total_tickets += 1
        if statut == "present": total_present += 1
        elif statut == "manquant": total_manquant += 1
        else: total_sans += 1

    # Construire le HTML
    def badge(statut):
        if statut == "present": return '<span style="background:#065f46;color:#6ee7b7;padding:3px 10px;border-radius:20px;font-size:12px;font-weight:700">✅ PDF présent</span>'
        if statut == "manquant": return '<span style="background:#7f1d1d;color:#fca5a5;padding:3px 10px;border-radius:20px;font-size:12px;font-weight:700">❌ PDF MANQUANT</span>'
        return '<span style="background:#374151;color:#9ca3af;padding:3px 10px;border-radius:20px;font-size:12px;font-weight:700">— Sans PDF</span>'

    cartes_orgs = ""
    for co, info in sorted(orgs.items(), key=lambda x: -x[1]["manquant"]):
        lignes = ""
        for tk in info["tickets"]:
            date_courte = tk["date"][:16].replace("T", " ") if tk["date"] else ""
            lignes += f'''<tr style="border-bottom:1px solid rgba(255,255,255,.08)">
                <td style="padding:8px;font-size:13px;color:#fff">{tk["acheteur"]}</td>
                <td style="padding:8px;font-size:13px;color:#c4b5fd">{tk["jeu"]}</td>
                <td style="padding:8px;font-size:12px;color:#94a3b8">{tk["serie"]}</td>
                <td style="padding:8px;font-size:12px;color:#64748b">{tk["code_acheteur"]}</td>
                <td style="padding:8px;font-size:11px;color:#64748b">{date_courte}</td>
                <td style="padding:8px;text-align:right">{badge(tk["statut"])}</td>
            </tr>'''
        alerte = ""
        if info["manquant"] > 0:
            alerte = f'<div style="background:#7f1d1d;color:#fca5a5;padding:8px 12px;border-radius:8px;margin-bottom:10px;font-size:13px;font-weight:600">⚠️ {info["manquant"]} PDF manquant(s) — ces joueuses ne peuvent pas ouvrir leur ticket !</div>'
        cartes_orgs += f'''<div style="background:#1e1b3a;border:1px solid #3730a3;border-radius:14px;padding:18px;margin-bottom:18px">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;flex-wrap:wrap;gap:8px">
                <div style="font-size:18px;font-weight:800;color:#fff">👤 {info["nom"]}</div>
                <div style="font-size:12px;color:#94a3b8">Code : {co}</div>
            </div>
            <div style="display:flex;gap:10px;margin-bottom:12px;flex-wrap:wrap">
                <div style="background:#065f46;color:#6ee7b7;padding:6px 14px;border-radius:8px;font-size:13px;font-weight:700">✅ {info["present"]} présents</div>
                <div style="background:#7f1d1d;color:#fca5a5;padding:6px 14px;border-radius:8px;font-size:13px;font-weight:700">❌ {info["manquant"]} manquants</div>
                <div style="background:#374151;color:#9ca3af;padding:6px 14px;border-radius:8px;font-size:13px;font-weight:700">— {info["sans"]} sans PDF</div>
            </div>
            {alerte}
            <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse">
                <tr style="border-bottom:2px solid #3730a3">
                    <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Joueuse</th>
                    <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Jeu</th>
                    <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Série</th>
                    <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Code</th>
                    <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Date</th>
                    <th style="padding:8px;text-align:right;font-size:12px;color:#a78bfa">État PDF</th>
                </tr>
                {lignes}
            </table></div>
        </div>'''

    if not orgs:
        cartes_orgs = '<div style="text-align:center;color:#94a3b8;padding:40px">Aucun ticket trouvé' + (f' pour le code {org_filtre}' if org_filtre else '') + '.</div>'

    titre_filtre = f' — {DB.get("codes", {}).get(org_filtre, {}).get("nom", org_filtre)}' if org_filtre else ''

    html = f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1">
    <title>Diagnostic PDF{titre_filtre}</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:-apple-system,system-ui,sans-serif;padding:18px;color:#fff">
    <div style="max-width:900px;margin:0 auto">
        <div style="text-align:center;margin-bottom:8px">
            <div style="font-size:14px;font-weight:800;color:#a855f7">🎱 TICKET BINGO</div>
            <h1 style="font-size:22px;margin:6px 0;color:#fff">🔍 Diagnostic des cartes (PDF){titre_filtre}</h1>
        </div>
        <div style="display:flex;gap:10px;justify-content:center;margin-bottom:20px;flex-wrap:wrap">
            <div style="background:#1e293b;padding:10px 18px;border-radius:10px;text-align:center">
                <div style="font-size:22px;font-weight:800;color:#fff">{total_tickets}</div>
                <div style="font-size:11px;color:#94a3b8">Tickets total</div></div>
            <div style="background:#065f46;padding:10px 18px;border-radius:10px;text-align:center">
                <div style="font-size:22px;font-weight:800;color:#6ee7b7">{total_present}</div>
                <div style="font-size:11px;color:#a7f3d0">PDF présents</div></div>
            <div style="background:#7f1d1d;padding:10px 18px;border-radius:10px;text-align:center">
                <div style="font-size:22px;font-weight:800;color:#fca5a5">{total_manquant}</div>
                <div style="font-size:11px;color:#fecaca">PDF manquants</div></div>
        </div>
        {cartes_orgs}
        <div style="text-align:center;margin-top:20px;font-size:12px;color:#64748b">
            Astuce : ajoute <code style="color:#a78bfa">?org=CODE</code> à l'adresse pour filtrer un organisateur précis.
        </div>
    </div></body></html>'''

# 🎁 DÉDOMMAGEMENT HEINI — Route admin
@app.route('/dedommagement-heini', methods=['GET', 'POST'])
def dedommagement_heini():
    if request.method == 'GET':
        return '''<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Dedommagement</title><style>body{font-family:system-ui;background:#7c3aed;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px}.box{background:#fff;border-radius:16px;padding:40px;max-width:400px;width:100%}h1{color:#7c3aed;text-align:center}input{width:100%;padding:12px;border:2px solid #e2e8f0;border-radius:8px;margin:20px 0;font-size:16px}button{width:100%;padding:14px;background:#7c3aed;color:#fff;border:0;border-radius:8px;font-size:16px;font-weight:600}.r{margin-top:15px;padding:15px;border-radius:8px;text-align:center}</style></head><body><div class="box"><h1>Dedommagement</h1><form id="f"><input type="password" id="a" placeholder="Code admin" required><button type="submit">Valider</button><div id="r"></div></form></div><script>document.getElementById("f").addEventListener("submit",async e=>{e.preventDefault();const r=await fetch("/dedommagement-heini",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:"admin="+encodeURIComponent(document.getElementById("a").value)});const d=await r.json();document.getElementById("r").innerHTML="<p>"+d.msg+"</p>"});</script></body></html>'''
    global DB
    admin = request.form.get('admin', '').strip()
    if admin != "ADMIN2024":
        return {"ok": False, "msg": "Code admin incorrect"}, 403
    try:
        DB = load_data()
        pions = DB.get("pions_joueurs", {})
        codes_a_credit = ["ITNLY9","MAJGAU","H6248Z","UM2MQE","BB1CP6","UN2B1Z","JML3U0","V2YPW2","HYJ1NG","6Z2K8U","WMWN2Z","PLC4IQ","VJ9LQU","QJ1MQU","QGVXNI","Q6ZJF5","NR5FUW","MG8S9K","KSOI4J","KJYMGI","GOUJ35","ET9R4I","DL3PUD","9LSL26","397LAI","NPE3GO"]
        for code in codes_a_credit:
            if code not in pions:
                pions[code] = {}
            pions[code]["100"] = pions[code].get("100", 0) + 1
        DB["pions_joueurs"] = pions
        save_data()
        return {"ok": True, "msg": "26 joueuses recreditees de 100 XPF chacune"}
    except Exception as e:
        return {"ok": False, "msg": f"Erreur : {str(e)}"}
# ============================================================
# 🛟 SAUVEGARDES HORODATEES AUTOMATIQUES + RESTAURATION 1 CLIC
# Ajout du 19/06/2026 — protege contre toute perte de donnees.
# L'appli se photographie toute seule plusieurs fois par jour et
# garde plusieurs jours d'historique. Si quoi que ce soit tourne
# mal, on revient a la photo d'avant en un clic.
# 100% additif : ne touche a aucune logique d'argent existante.
# ============================================================
import shutil as _shutil_bk
import threading as _threading_bk
import time as _time_bk
import glob as _glob_bk

BACKUP_DIR = "/data/sauvegardes"
BACKUP_INTERVAL_SECONDES = 20 * 60      # une photo toutes les 20 minutes
BACKUP_MAX_FICHIERS = 300               # garder les 300 dernieres (~4 jours)
_BACKUP_THREAD_DEMARRE = [False]


def _est_admin_code(code):
    """Verifie qu'un code est un code admin actif (anti-acces non autorise)."""
    try:
        code = (code or "").strip().upper()
        if not code:
            return False
        fresh = load_data()
        info = fresh.get("codes", {}).get(code)
        return bool(info and info.get("actif") and info.get("admin"))
    except Exception:
        return False


def creer_sauvegarde_horodatee(raison="auto"):
    """Copie le fichier de donnees actuel dans un fichier horodate.
    Retourne le chemin cree, ou None si rien a sauvegarder."""
    try:
        os.makedirs(BACKUP_DIR, exist_ok=True)
        if not os.path.exists(DATA_FILE):
            return None
        horodatage = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        raison_propre = "".join(c for c in str(raison) if c.isalnum() or c in "-_")[:30] or "auto"
        nom = f"ticketbingo_{horodatage}_{raison_propre}.json"
        chemin = os.path.join(BACKUP_DIR, nom)
        _shutil_bk.copy2(DATA_FILE, chemin)
        _purger_vieilles_sauvegardes()
        print(f"[SAUVEGARDE OK] {nom}")
        return chemin
    except Exception as e:
        print(f"[SAUVEGARDE ERR] {e}")
        return None


def _purger_vieilles_sauvegardes():
    """Ne garde que les BACKUP_MAX_FICHIERS plus recentes (borne le disque)."""
    try:
        fichiers = sorted(_glob_bk.glob(os.path.join(BACKUP_DIR, "ticketbingo_*.json")))
        surplus = len(fichiers) - BACKUP_MAX_FICHIERS
        for f in fichiers[:max(0, surplus)]:
            try:
                os.remove(f)
            except Exception:
                pass
    except Exception:
        pass


def _lister_sauvegardes():
    """Liste les sauvegardes, de la plus recente a la plus ancienne."""
    resultats = []
    try:
        fichiers = sorted(_glob_bk.glob(os.path.join(BACKUP_DIR, "ticketbingo_*.json")), reverse=True)
        for f in fichiers:
            try:
                st = os.stat(f)
                nom = os.path.basename(f)
                # Date lisible depuis le nom : ticketbingo_YYYYMMDD_HHMMSS_raison.json
                parties = nom.replace("ticketbingo_", "").replace(".json", "").split("_")
                date_lisible = nom
                raison = "auto"
                if len(parties) >= 2:
                    d, h = parties[0], parties[1]
                    if len(d) == 8 and len(h) == 6:
                        date_lisible = f"{d[6:8]}/{d[4:6]}/{d[0:4]} a {h[0:2]}h{h[2:4]}"
                    if len(parties) >= 3:
                        raison = parties[2]
                resultats.append({
                    "nom": nom,
                    "date": date_lisible,
                    "raison": raison,
                    "taille_ko": round(st.st_size / 1024, 1),
                })
            except Exception:
                pass
    except Exception:
        pass
    return resultats


def _resume_donnees(donnees):
    """Petit resume d'un jeu de donnees (pour confirmer visuellement avant restauration)."""
    try:
        nb_joueurs = len(donnees.get("pions_joueurs", {}))
        nb_codes = len(donnees.get("codes", {}))
        nb_orgs = len(donnees.get("pions_org", {}))
        # Total des pions (toutes valeurs confondues) en nombre de pieces
        total_pions = 0
        for poche in donnees.get("pions_joueurs", {}).values():
            if isinstance(poche, dict):
                for v in poche.values():
                    try:
                        total_pions += int(v)
                    except Exception:
                        pass
        return {"joueurs": nb_joueurs, "codes": nb_codes, "organisateurs": nb_orgs, "pions_total": total_pions}
    except Exception:
        return {"joueurs": "?", "codes": "?", "organisateurs": "?", "pions_total": "?"}


def _boucle_sauvegardes_auto():
    """Boucle de fond : une photo au demarrage, puis toutes les 20 min."""
    # Petite photo de demarrage (utile apres chaque redeploiement)
    try:
        creer_sauvegarde_horodatee("demarrage")
    except Exception:
        pass
    while True:
        try:
            _time_bk.sleep(BACKUP_INTERVAL_SECONDES)
            creer_sauvegarde_horodatee("auto")
        except Exception as e:
            print(f"[SAUVEGARDE BOUCLE ERR] {e}")
            _time_bk.sleep(60)


def _demarrer_sauvegardes_auto():
    """Demarre le thread de sauvegarde une seule fois."""
    if _BACKUP_THREAD_DEMARRE[0]:
        return
    _BACKUP_THREAD_DEMARRE[0] = True
    t = _threading_bk.Thread(target=_boucle_sauvegardes_auto, daemon=True)
    t.start()
    print("[SAUVEGARDES] Thread de sauvegardes automatiques demarre.")


_demarrer_sauvegardes_auto()


