# === COMMENTAIRES MICRO (joueuse -> organisatrice) ===
def _verifier_doleance(code, message):
    """ANTI-MENSONGE — Vérifie une affirmation de joueuse contre les vraies données.
    Renvoie {sujet, statut, detail} ; statut = 'dementi' (contredit), 'confirme'
    (exact) ou 'indetermine'. Renvoie None si aucune affirmation détectée."""
    global DB
    try:
        m = (message or "").lower()
        code = (code or "").upper().strip()
        if not code:
            return None
        nie = any(x in m for x in ["pas ", "rien", "jamais", "manque", "aucun", "non recu", "pas recu", "pas reçu", "n'ai pas", "peux pas", "arrive pas", "marche pas"])
        # 1) "Je n'ai pas reçu mes pions"
        if ("pion" in m or "credit" in m or "crédit" in m or "solde" in m) and nie:
            pions = DB.get("pions_joueurs", {}).get(code, {})
            bonus = DB.get("pions_bonus_joueurs", {}).get(code, {})
            total = _xpf_total_pions(pions) + _xpf_total_pions(bonus)
            cand = []
            for t in DB.get("transactions_joueur_org", []):
                if (t.get("code_joueur", "") or "").upper() == code:
                    cand.append((t.get("date", ""), int(t.get("montant_total", 0) or 0), "organisatrice"))
            for c in DB.get("credits_admin", []):
                if (c.get("code_joueur", "") or "").upper() == code:
                    cand.append((c.get("date", ""), int(c.get("valeur_pion", 0) or 0) * int(c.get("nb_pions", 0) or 0), "admin"))
            for c in DB.get("credits_masse", []):
                if code in [str(x).upper() for x in (c.get("codes") or [])]:
                    cand.append((c.get("date", ""), int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0), "groupe"))
            cand.sort(key=lambda x: str(x[0]), reverse=True)
            if total > 0 or cand:
                det = f"Portefeuille actuel : {total} XPF de pions."
                if cand:
                    d0 = cand[0]
                    det += f" Dernier crédit : {d0[1]} XPF ({d0[2]}) le {str(d0[0])[:16].replace('T',' ')}."
                return {"sujet": "Pions reçus", "statut": "dementi", "detail": det}
            return {"sujet": "Pions reçus", "statut": "confirme", "detail": "Aucun pion ni crédit trouvé pour ce code — l'affirmation semble exacte."}
        # 2) "Je n'arrive pas à ouvrir le PDF"
        if "pdf" in m or "feuille" in m or "ouvr" in m or "telecharg" in m or "télécharg" in m:
            tk = None
            for t in DB.get("tickets", []):
                if (t.get("code_acheteur", "") or "").upper() == code:
                    tk = t
                    if t.get("pdf_url"):
                        break
            if tk and tk.get("pdf_url"):
                return {"sujet": "PDF du ticket", "statut": "dementi", "detail": f"Le ticket existe AVEC un PDF ({tk.get('jeu','?')} · série {tk.get('serie','?')}). Souci d'appareil/connexion plutôt que d'attribution."}
            if tk:
                return {"sujet": "PDF du ticket", "statut": "confirme", "detail": "Le ticket existe mais SANS PDF rattaché — l'affirmation semble exacte (PDF à régénérer)."}
            return {"sujet": "PDF du ticket", "statut": "indetermine", "detail": "Aucun ticket trouvé pour ce code."}
        # 3) "Je n'ai pas pointé mon ticket"
        if ("point" in m or "coch" in m) and nie:
            coches = DB.get("coches", {})
            n = 0
            if isinstance(coches, dict):
                v = coches.get(code)
                if isinstance(v, (list, dict)):
                    n = len(v)
            if n > 0:
                return {"sujet": "Pointage", "statut": "dementi", "detail": f"{n} case(s) pointée(s) enregistrée(s) pour ce code."}
            return {"sujet": "Pointage", "statut": "indetermine", "detail": "Aucun pointage enregistré côté serveur — à vérifier (le pointage est souvent local au téléphone)."}
        return None
    except Exception:
        return None


def _reponse_robot_joueur(code, message):
    """ROBOT — Réponse automatique amicale affichée à la joueuse, basée sur la
    vérification des données réelles."""
    try:
        v = _verifier_doleance(code, message)
        if not v:
            return "🤖 Merci, ton message a bien été transmis à l'organisatrice. Elle te répondra dès que possible."
        sujet = v.get("sujet")
        st = v.get("statut")
        det = v.get("detail", "")
        if sujet == "Pions reçus":
            if st == "dementi":
                return "🤖 Bonne nouvelle : tes pions sont bien là ! " + det + " Ouvre l'onglet 🪙 Mes Pions pour les voir."
            return "🤖 Je ne vois aucun pion crédité à ton code pour l'instant. J'ai prévenu l'organisatrice, elle va vérifier."
        if sujet == "PDF du ticket":
            if st == "dementi":
                return "🤖 Ton ticket et son PDF existent bien. Réessaie le bouton 🎯 Jouer et vérifie ta connexion internet. Si ça bloque encore, l'organisatrice peut te le renvoyer."
            if st == "confirme":
                return "🤖 Ton ticket n'a pas encore de PDF rattaché. J'ai prévenu l'organisatrice, elle va le régénérer pour toi."
            return "🤖 Je ne trouve pas encore ton ticket. Vérifie bien ton code, ou demande à l'organisatrice."
        if sujet == "Pointage":
            if st == "dementi":
                return "🤖 Ton pointage est bien enregistré, tout est bon !"
            return "🤖 Le pointage se fait sur ton téléphone : entre ton code dans ton ticket et les numéros se cochent tout seuls au tirage."
        return "🤖 Merci, l'organisatrice a bien reçu ton message."
    except Exception:
        return "🤖 Merci, ton message a bien été transmis à l'organisatrice."


# Horaire HABITUEL des tournois (début, fin). weekday() : lundi=0 ... dimanche=6
_HORAIRES_TOURNOI = {
    0: ("17:30", "23:30"),  # lundi
    1: ("17:30", "23:30"),  # mardi
    2: ("17:30", "23:30"),  # mercredi
    3: ("17:30", "23:30"),  # jeudi
    4: ("17:30", "23:30"),  # vendredi
    5: ("13:00", "23:59"),  # samedi — jusqu'à minuit
    6: ("13:00", "19:00"),  # dimanche
}


def _fenetre_tournoi():
    """Renvoie (ouvert, prochain_iso, message). L'app est OUVERTE aux joueuses de
    1h avant le début du tournoi du jour jusqu'à 6h après. Horaire habituel :
    lundi→vendredi 17h30, samedi→dimanche 13h00. Les tournois programmés (spéciaux)
    ouvrent aussi la fenêtre. En cas de doute -> ouvert (on ne bloque jamais)."""
    try:
        now = datetime.datetime.now()
        prochain = None

        def _fenetre_de(debut):
            return (debut - datetime.timedelta(hours=1), debut + datetime.timedelta(hours=6))

        # 1) Horaire HABITUEL du jour
        hs = _HORAIRES_TOURNOI.get(now.weekday())
        if hs:
            sh, sm = [int(x) for x in hs[0].split(":")]
            eh, em = [int(x) for x in hs[1].split(":")]
            debut = now.replace(hour=sh, minute=sm, second=0, microsecond=0)
            fin = now.replace(hour=eh, minute=em, second=59, microsecond=0)
            ouv = debut - datetime.timedelta(hours=1)
            if ouv <= now <= fin:
                return True, debut.isoformat(), ""
            if now < ouv:
                prochain = debut

        # 2) Tournois PROGRAMMÉS (spéciaux, à un autre horaire)
        for t in DB.get("tournois_programmes", []):
            if not isinstance(t, dict):
                continue
            try:
                dt = datetime.datetime.fromisoformat(str(t.get("date_heure", "")).replace("Z", ""))
            except Exception:
                continue
            ouv, fin = _fenetre_de(dt)
            if ouv <= now <= fin:
                return True, dt.isoformat(), ""
            if now < ouv and (prochain is None or dt < prochain):
                prochain = dt

        # 3) Sinon, prochain tournoi habituel (aujourd'hui plus tard, ou un jour suivant)
        if prochain is None:
            for i in range(1, 8):
                j = now + datetime.timedelta(days=i)
                hsj = _HORAIRES_TOURNOI.get(j.weekday())
                if hsj:
                    hh, mm = [int(x) for x in hsj[0].split(":")]
                    prochain = j.replace(hour=hh, minute=mm, second=0, microsecond=0)
                    break

        if prochain is not None:
            return False, prochain.isoformat(), "L'application ouvre 1h avant le tournoi (le " + prochain.strftime("%d/%m à %H:%M") + ")."
        return False, None, "Aucun tournoi programmé pour le moment."
    except Exception:
        return True, None, ""


def _robot_repond(code, message):
    """ROBOT-GUIDE — Répond aux questions des joueuses toute la journée (FAQ +
    vérification des données)."""
    try:
        m = (message or "").lower()
        ouvert, prochain_iso, _ = _fenetre_tournoi()
        if any(w in m for w in ["quand", "heure", "prochain tournoi", "a quelle", "à quelle", "c'est quand", "date du tournoi"]):
            if prochain_iso:
                try:
                    dt = datetime.datetime.fromisoformat(prochain_iso)
                    return "🤖 Le prochain tournoi est le " + dt.strftime("%d/%m à %H:%M") + ". L'application s'ouvre 1h avant. À très vite ! 🌺"
                except Exception:
                    pass
            return "🤖 Aucun tournoi n'est programmé pour le moment. Surveille les annonces de l'organisatrice ! 🌺"
        if ("achet" in m or "command" in m or "recharg" in m) and "pion" in m:
            return "🤖 Pour acheter des pions : ouvre l'onglet 🪙 Mes Pions, choisis le montant et confirme. L'organisatrice valide ton paiement et tes pions arrivent. 💛"
        if "comment" in m and ("jou" in m or "march" in m or "fonctionn" in m):
            return "🤖 C'est simple : 1) achète tes pions, 2) achète tes tickets pour le jeu annoncé, 3) ton ticket se coche tout seul au tirage. Bonne chance ! 🍀"
        if "retir" in m or "encaiss" in m or ("gagn" in m and "argent" in m):
            return "🤖 Quand tu gagnes, tes gains arrivent en pions. Pour récupérer en argent, fais une demande de retrait : l'organisatrice te paie. 💰"
        if ("pdf" in m or "feuille" in m) and ("comment" in m or "ouvr" in m or "trouv" in m):
            return "🤖 Pour ouvrir ton ticket : onglet 🎮 ton ticket, puis bouton 🎯 Jouer. Si le PDF tarde, vérifie ta connexion internet. 📄"
        return _reponse_robot_joueur(code, message)
    except Exception:
        return "🤖 Merci, ton message a bien été reçu."


